/**
 * main-features.js
 * Contains the rendering logic for the main dashboard and its modules.
 */

// Helper to get current user from local or session storage
function getCurrentUser() {
    const localUser = localStorage.getItem('currentUser');
    const sessionUser = sessionStorage.getItem('currentUser');

    if (localUser) return JSON.parse(localUser);
    if (sessionUser) return JSON.parse(sessionUser);
    return null;
}

// Helper to save current user to local or session storage
function saveCurrentUser(user) {
    if (localStorage.getItem('currentUser')) {
        localStorage.setItem('currentUser', JSON.stringify(user));
    } else {
        sessionStorage.setItem('currentUser', JSON.stringify(user));
    }
}

document.addEventListener('DOMContentLoaded', function () {
    // Initialize theme first
    if (typeof initializeTheme === 'function') {
        initializeTheme();
    } else {
        // Fallback initialization
        if (localStorage.getItem('theme') === 'dark') {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }

    // Initialize dashboard or public portal based on role
    const user = getCurrentUser();

    if (user && user.role === 'User - Committee') {
        // Now treat User role like Staff - use admin layout and dashboard
        renderSidebar();
        showSection('dashboard');
    } else {
        // Standard Admin/Staff layout
        renderSidebar();
        showSection('dashboard');
    }

    // Update user info from storage for all roles
    updateUserInfo();

    // Reveal App Container and Hide Loader
    // Reveal App Container and Hide Loader
    // Loader removed as per request
    const appContainer = document.getElementById('app-container');
    if (appContainer) appContainer.classList.remove('opacity-0');

    // Start background polling for real-time updates (notifications & sessions)
    simulateRealTimeUpdates();
});

// Global Helper: Load Staff List
window.loadStaffList = async function () {
    if (window.cachedStaffList) return window.cachedStaffList;
    try {
        const response = await fetch('../api/api_users.php');
        const data = await response.json();
        if (data.success) {
            window.cachedStaffList = data.users;
            return data.users;
        }
        return [];
    } catch (e) {
        console.error('Error loading staff list:', e);
        return [];
    }
};

// Global Helper: Render Staff Options
window.renderStaffOptions = function (users, selectedId = null) {
    if (!users || users.length === 0) return '<option value="">No users available</option>';

    return users.map(user => {
        const isSelected = selectedId && (user.user_id == selectedId) ? 'selected' : '';
        return `<option value="${user.user_id}" ${isSelected}>${user.user_name || user.username} (${user.user_role})</option>`;
    }).join('');
};

// Global Helper: Render Staff Checkboxes
window.renderStaffCheckboxes = function (users, selectedIds = []) {
    if (!users || users.length === 0) return '<p class="text-xs text-gray-500 italic p-2">No staff available</p>';

    // Ensure selectedIds is an array
    const selectedSet = new Set();
    if (Array.isArray(selectedIds)) {
        selectedIds.forEach(id => selectedSet.add(id.toString()));
    } else if (typeof selectedIds === 'string' && selectedIds) {
        selectedIds.split(',').forEach(id => selectedSet.add(id.trim()));
    }

    return users.map(user => {
        const isChecked = selectedSet.has(user.user_id.toString()) ? 'checked' : '';
        const initial = (user.user_name || user.username || 'U').charAt(0).toUpperCase();

        return `
            <label class="flex items-center gap-3 p-2 hover:bg-gray-50 dark:hover:bg-slate-700/50 rounded-lg cursor-pointer transition group">
                <input type="checkbox" value="${user.user_id}" ${isChecked} class="staff-checkbox w-4 h-4 text-red-600 border-gray-300 rounded focus:ring-red-500">
                <div class="w-7 h-7 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center text-red-600 dark:text-red-400 font-bold text-[10px]">
                    ${initial}
                </div>
                <div class="flex-1 min-w-0">
                    <p class="text-xs font-semibold text-gray-900 dark:text-white truncate group-hover:text-red-600 transition-colors">${user.user_name || user.username}</p>
                    <p class="text-[10px] text-gray-500 dark:text-dark-muted truncate">${user.user_role}</p>
                </div>
            </label>
        `;
    }).join('');
};

// Global Helper: Refresh Staff List for Agenda based on Session
window.refreshAgendaStaffList = async function (sessionId) {
    const staffContainer = document.getElementById('agenda-staff-container');
    if (!staffContainer) return;

    if (!sessionId) {
        staffContainer.innerHTML = '<p class="text-xs text-gray-500 italic p-2 text-center">Select a session to see assigned staff</p>';
        return;
    }

    // Use cache if available to avoid redundant fetches
    if (window.agendaStaffCache && window.agendaStaffCache[sessionId]) {
        const staff = window.agendaStaffCache[sessionId];
        if (staffContainer) staffContainer.innerHTML = renderStaffCheckboxes(staff);

        const assignToSelects = document.querySelectorAll('.agenda-item-assigned-to');
        if (assignToSelects.length > 0 && typeof window.renderStaffOptions === 'function') {
            const optionsHtml = '<option value="">Select User</option>' + window.renderStaffOptions(staff);
            assignToSelects.forEach(select => {
                const currentValue = select.value;
                if (!currentValue || currentValue === "") {
                    select.innerHTML = optionsHtml;
                }
            });
        }
        // Continue to check for date constraints even if staff is cached
    } else {
        // Show loading state ONLY if NOT cached
        staffContainer.innerHTML = `
            <div class="flex justify-center p-4">
                <div class="animate-spin rounded-full h-5 w-5 border-b-2 border-red-600"></div>
            </div>
        `;
    }

    try {
        const response = await fetch(`../api/api_sessions.php?id=${sessionId}`);
        const data = await response.json();

        if (data.success && data.session && data.session.assigned_staff) {
            const staff = data.session.assigned_staff;

            // Update cache
            if (!window.agendaStaffCache) window.agendaStaffCache = {};
            window.agendaStaffCache[sessionId] = staff;

            // Populate checkboxes
            if (staffContainer) staffContainer.innerHTML = renderStaffCheckboxes(staff);

            // Also populate all Assign To dropdowns if they exist
            const assignToSelects = document.querySelectorAll('.agenda-item-assigned-to');
            if (assignToSelects.length > 0 && typeof window.renderStaffOptions === 'function') {
                const optionsHtml = '<option value="">Select User</option>' + window.renderStaffOptions(staff);
                assignToSelects.forEach(select => {
                    const currentValue = select.value;
                    // Only update if empty or if we just added this block
                    if (!currentValue || currentValue === "" || select.innerHTML.includes('Select Session First')) {
                        select.innerHTML = optionsHtml;
                    }
                });
            }

            // Set Date Constraints based on session date for all due date inputs
            const dueDateInputs = document.querySelectorAll('.agenda-item-due-date');
            if (dueDateInputs.length > 0 && data.session.session_date) {
                const sessionDateStr = data.session.session_date;
                const sessionDate = new Date(sessionDateStr);

                // Max date is the day before the session
                const maxDate = new Date(sessionDate);
                maxDate.setDate(maxDate.getDate() - 1);
                const maxDateStr = maxDate.toISOString().split('T')[0];

                // Min date is today
                const todayStr = new Date().toISOString().split('T')[0];

                dueDateInputs.forEach(input => {
                    input.max = maxDateStr;
                    input.min = todayStr;
                });
            }
        } else {
            const msg = '<p class="text-xs text-center text-gray-500 italic p-4">No staff assigned to this session.</p>';
            if (staffContainer) staffContainer.innerHTML = msg;
            const assignToSelect = document.getElementById('agenda-item-assigned-to');
            if (assignToSelect) assignToSelect.innerHTML = '<option value="">No staff assigned</option>';
        }
    } catch (e) {
        console.error('Error refreshing agenda staff:', e);
        if (staffContainer) staffContainer.innerHTML = '<p class="text-xs text-red-500 p-2 text-center">Error loading staff list</p>';
    }
};

