async function updateUserInfo() {
    let user = getCurrentUser();
    if (!user) return;

    // Refresh user data from API to get latest fields (like last_login)
    try {
        const response = await fetch(`../api/api_users.php?id=${user.id || user.user_id}`);
        const data = await response.json();
        if (data.success && data.user) {
            // Map API fields to the format expected by the app if necessary
            const updatedUser = {
                ...user,
                name: data.user.user_name || user.name,
                role: data.user.user_role || user.role,
                email: data.user.email || user.email,
                last_login: data.user.last_login || user.last_login,
                avatar: data.user.avatar_url || user.avatar
            };
            saveCurrentUser(updatedUser);
            user = updatedUser;
        }
    } catch (e) {
        console.error("Failed to refresh user data:", e);
    }

    // Update sidebar info
    const sidebarName = document.getElementById('sidebar-user-name');
    const sidebarRole = document.getElementById('sidebar-user-role');

    if (sidebarName) sidebarName.textContent = user.name;
    if (sidebarRole) sidebarRole.textContent = user.role;

    // Update mobile sidebar info
    const mobileName = document.getElementById('mobile-user-name');
    const mobileRole = document.getElementById('mobile-user-role');

    if (mobileName) mobileName.textContent = user.name;
    if (mobileRole) mobileRole.textContent = user.role;

    // Update navbar profile info
    const navbarName = document.getElementById('navbar-user-name');
    const navbarRole = document.getElementById('navbar-user-role');
    const dropdownDisplayName = document.getElementById('dropdown-user-display-name');
    const dropdownRoleLabel = document.getElementById('dropdown-user-role-label');
    const dropdownEmail = document.getElementById('dropdown-user-email');

    if (navbarName) navbarName.textContent = user.name;
    if (navbarRole) navbarRole.textContent = user.role;
    if (dropdownDisplayName) dropdownDisplayName.textContent = user.name;
    if (dropdownRoleLabel) dropdownRoleLabel.textContent = user.role;
    if (dropdownEmail) dropdownEmail.textContent = user.email;

    // Update Profile Picture
    updateNavbarProfilePicture(user.avatar || user.profilePicture);

    // Update Last Login in dashboard if visible
    const lastLoginEl = document.querySelector('[id^="dashboard-last-login"]');
    if (lastLoginEl && user.last_login) {
        lastLoginEl.textContent = formatDetailedDate(user.last_login);
    } else if (lastLoginEl) {
        lastLoginEl.textContent = 'First login session';
    }

    // ==============================
    // UI ADJUSTMENTS BASED ON ROLE
    // ==============================

    // 1. Hide/Show Settings Link in Dropdown
    const settingsLink = document.getElementById('dropdown-settings');
    if (settingsLink) {
        if (user.role === 'Super Admin' || user.role === 'Admin' || user.role === 'Administrator') {
            settingsLink.style.display = 'block';
        } else {
            settingsLink.style.display = 'none';
        }
    }

    // 2. Update Breadcrumb Home Link
    const breadcrumbHome = document.getElementById('breadcrumb-home');
    if (breadcrumbHome) {
        breadcrumbHome.setAttribute('onclick', "showSection('dashboard')");
    }
}

// Helper to format date nicely
function formatDetailedDate(dateStr) {
    if (!dateStr || dateStr === '0000-00-00 00:00:00') return 'First login session';
    const date = new Date(dateStr.replace(/-/g, "/")); // Better parsing for cross-browser
    if (isNaN(date)) return dateStr;

    return date.toLocaleString('en-US', {
        month: 'long',
        day: 'numeric',
        year: 'numeric',
        hour: 'numeric',
        minute: '2-digit',
        hour12: true
    });
}


// Custom Unsaved Changes Modal
// Custom Unsaved Changes Modal
function showUnsavedChangesModal(callback, options = {}) {
    const existingModal = document.getElementById('unsavedChangesModal');
    if (existingModal) existingModal.remove();

    const title = options.title || 'Unsaved Changes';
    const message = options.message || 'You have unsaved changes. Are you sure you want to leave?';
    const description = options.description || 'If you leave this page, your changes will be lost. This action cannot be undone.';
    const confirmText = options.confirmText || 'Leave Page';

    const modalHtml = `
    <div id="unsavedChangesModal" class="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center justify-center animate-fade-in">
        <div class="bg-white dark:bg-dark-card rounded-xl shadow-2xl max-w-md w-full mx-4 overflow-hidden transform scale-100 animate-fade-in-up border dark:border-dark-border">
            <div class="p-6">
                <div class="flex items-center gap-4 mb-4">
                    <div class="w-12 h-12 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center flex-shrink-0">
                        <i class="bi bi-exclamation-triangle-fill text-red-600 dark:text-red-400 text-xl"></i>
                    </div>
                    <div>
                        <h3 class="text-lg font-bold text-gray-900 dark:text-white">${title}</h3>
                        <p class="text-sm text-gray-500 dark:text-dark-muted">${message}</p>
                    </div>
                </div>
                <p class="text-gray-600 dark:text-dark-text text-sm leading-relaxed mb-6 pl-16">
                    ${description}
                </p>
                <div class="flex justify-end gap-3 px-4 pb-2">
                    <button onclick="closeUnsavedChangesModal()" class="px-4 py-2 bg-white dark:bg-dark-bg text-gray-700 dark:text-dark-text border border-gray-300 dark:border-dark-border rounded-lg hover:bg-gray-50 dark:hover:bg-slate-800 font-medium transition-colors text-sm">
                        Cancel
                    </button>
                    <button id="confirmUnsavedBtn" class="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium transition-colors shadow-lg shadow-red-500/30 text-sm">
                        ${confirmText}
                    </button>
                </div>
            </div>
        </div>
    </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);

    document.getElementById('confirmUnsavedBtn').onclick = function () {
        closeUnsavedChangesModal();
        if (callback) callback();
    };
}

function closeUnsavedChangesModal() {
    const modal = document.getElementById('unsavedChangesModal');
    if (modal) modal.remove();
}

/**
 * Premium Confirm Modal - returns a Promise
 * @param {Object} options {title, message, description, confirmText, cancelText, type}
 */
window.showConfirmModal = function (options = {}) {
    return new Promise((resolve) => {
        const existingModal = document.getElementById('customConfirmModal');
        if (existingModal) existingModal.remove();

        const title = options.title || 'Are you sure?';
        const message = options.message || 'Please confirm this action.';
        const description = options.description || '';
        const confirmText = options.confirmText || 'Confirm';
        const cancelText = options.cancelText || 'Cancel';
        const type = options.type || 'danger'; // 'danger', 'info', 'warning', 'success'

        const colors = {
            danger: 'red',
            info: 'blue',
            warning: 'amber',
            success: 'green'
        };
        const color = colors[type] || 'red';

        const icons = {
            danger: 'bi-exclamation-triangle-fill',
            info: 'bi-info-circle-fill',
            warning: 'bi-exclamation-circle-fill',
            success: 'bi-check-circle-fill'
        };
        const icon = icons[type] || 'bi-exclamation-triangle-fill';

        const modalHtml = `
        <div id="customConfirmModal" class="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center animate-fade-in p-4">
            <div class="bg-white dark:bg-dark-card rounded-2xl shadow-2xl max-w-md w-full overflow-hidden transform scale-100 animate-fade-in-up border border-gray-100 dark:border-dark-border">
                <div class="p-8">
                    <div class="flex items-center gap-5 mb-6">
                        <div class="w-14 h-14 rounded-2xl bg-${color}-50 dark:bg-${color}-900/20 flex items-center justify-center flex-shrink-0 shadow-inner">
                            <i class="bi ${icon} text-${color}-600 dark:text-${color}-400 text-2xl"></i>
                        </div>
                        <div>
                            <h3 class="text-xl font-black text-gray-900 dark:text-white">${title}</h3>
                            <p class="text-sm text-gray-500 dark:text-dark-muted font-medium">${message}</p>
                        </div>
                    </div>
                    ${description ? `<p class="text-gray-600 dark:text-dark-text text-sm leading-relaxed mb-8 pl-[76px] font-medium">${description}</p>` : ''}
                    <div class="flex justify-end gap-3">
                        <button id="cancelConfirmBtn" class="px-6 py-3 bg-gray-50 dark:bg-dark-bg text-gray-700 dark:text-dark-text border border-gray-200 dark:border-dark-border rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 font-bold transition-all text-sm">
                            ${cancelText}
                        </button>
                        <button id="okConfirmBtn" class="px-6 py-3 bg-${color}-600 text-white rounded-xl hover:bg-${color}-700 font-bold transition-all shadow-lg shadow-${color}-500/30 text-sm active:scale-95">
                            ${confirmText}
                        </button>
                    </div>
                </div>
            </div>
        </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        document.body.style.overflow = 'hidden';

        document.getElementById('okConfirmBtn').onclick = function () {
            const modal = document.getElementById('customConfirmModal');
            if (modal) modal.remove();
            document.body.style.overflow = '';
            resolve(true);
        };

        document.getElementById('cancelConfirmBtn').onclick = function () {
            const modal = document.getElementById('customConfirmModal');
            if (modal) modal.remove();
            document.body.style.overflow = '';
            resolve(false);
        };

        // Close on clicking overlay
        document.getElementById('customConfirmModal').onclick = function (e) {
            if (e.target === this) {
                this.remove();
                document.body.style.overflow = '';
                resolve(false);
            }
        };
    });
};

/**
 * Password confirmation modal that verifies the current user's password
 * against the server before allowing destructive actions (like delete).
 * Returns true if password is correct, false otherwise.
 */
window.promptPasswordConfirmation = function (options = {}) {
    return new Promise((resolve) => {
        const existingModal = document.getElementById('passwordConfirmModal');
        if (existingModal) existingModal.remove();

        const title = options.title || 'Confirm with Password';
        const message = options.message || 'For security reasons, please enter your password to continue.';
        const confirmText = options.confirmText || 'Confirm';
        const cancelText = options.cancelText || 'Cancel';

        const modalHtml = `
        <div id="passwordConfirmModal" class="fixed inset-0 bg-black/60 backdrop-blur-sm z-[110] flex items-center justify-center animate-fade-in p-4">
            <div class="bg-white dark:bg-dark-card rounded-2xl shadow-2xl max-w-md w-full overflow-hidden transform scale-100 animate-fade-in-up border border-gray-100 dark:border-dark-border">
                <div class="p-8">
                    <div class="flex items-center gap-5 mb-6">
                        <div class="w-14 h-14 rounded-2xl bg-red-50 dark:bg-red-900/20 flex items-center justify-center flex-shrink-0 shadow-inner">
                            <i class="bi bi-shield-lock-fill text-red-600 dark:text-red-400 text-2xl"></i>
                        </div>
                        <div>
                            <h3 class="text-xl font-black text-gray-900 dark:text-white">${title}</h3>
                            <p class="text-sm text-gray-500 dark:text-dark-muted font-medium">${message}</p>
                        </div>
                    </div>
                    <div class="pl-[76px] mb-2">
                        <label for="passwordConfirmInput" class="block text-xs font-semibold text-gray-600 dark:text-dark-muted mb-1">Password</label>
                        <input type="password" id="passwordConfirmInput" class="w-full px-3 py-2 border border-gray-300 dark:border-dark-border rounded-lg text-sm bg-gray-50 dark:bg-dark-bg text-gray-900 dark:text-dark-text focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-red-500" autocomplete="current-password" />
                        <p id="passwordConfirmError" class="mt-2 text-xs text-red-500 hidden"></p>
                    </div>
                    <div class="flex justify-end gap-3 mt-4">
                        <button id="passwordConfirmCancelBtn" class="px-6 py-3 bg-gray-50 dark:bg-dark-bg text-gray-700 dark:text-dark-text border border-gray-200 dark:border-dark-border rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 font-bold transition-all text-sm">
                            ${cancelText}
                        </button>
                        <button id="passwordConfirmOkBtn" class="px-6 py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 font-bold transition-all shadow-lg shadow-red-500/30 text-sm active:scale-95">
                            ${confirmText}
                        </button>
                    </div>
                </div>
            </div>
        </div>
        `;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
        document.body.style.overflow = 'hidden';

        const passwordInput = document.getElementById('passwordConfirmInput');
        const errorEl = document.getElementById('passwordConfirmError');
        const okBtn = document.getElementById('passwordConfirmOkBtn');
        const cancelBtn = document.getElementById('passwordConfirmCancelBtn');
        const modalRoot = document.getElementById('passwordConfirmModal');

        passwordInput.focus();

        async function handleConfirm() {
            const password = passwordInput.value.trim();
            if (!password) {
                errorEl.textContent = 'Please enter your password.';
                errorEl.classList.remove('hidden');
                return;
            }

            // Loading state
            okBtn.disabled = true;
            okBtn.textContent = 'Verifying...';
            errorEl.classList.add('hidden');

            try {
                const response = await fetch('../config/verify_password.php', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ password })
                });

                const result = await response.json();
                if (response.ok && result.success) {
                    if (modalRoot) modalRoot.remove();
                    document.body.style.overflow = '';
                    resolve(true);
                } else {
                    errorEl.textContent = result.message || 'Incorrect password. Please try again.';
                    errorEl.classList.remove('hidden');
                    okBtn.disabled = false;
                    okBtn.textContent = confirmText;
                }
            } catch (e) {
                console.error('Password verification failed:', e);
                errorEl.textContent = 'Unable to verify password. Please try again.';
                errorEl.classList.remove('hidden');
                okBtn.disabled = false;
                okBtn.textContent = confirmText;
            }
        }

        okBtn.onclick = handleConfirm;

        cancelBtn.onclick = function () {
            if (modalRoot) modalRoot.remove();
            document.body.style.overflow = '';
            resolve(false);
        };

        modalRoot.onclick = function (e) {
            if (e.target === modalRoot) {
                modalRoot.remove();
                document.body.style.overflow = '';
                resolve(false);
            }
        };

        passwordInput.addEventListener('keydown', function (e) {
            if (e.key === 'Enter') {
                e.preventDefault();
                handleConfirm();
            }
        });
    });
};

/**
 * Premium Alert Modal - returns a Promise
 * @param {Object} options {title, message, btnText, type}
 */
window.showAlertModal = function (options = {}) {
    return new Promise((resolve) => {
        const existingModal = document.getElementById('customAlertModal');
        if (existingModal) existingModal.remove();

        const title = options.title || 'Notification';
        const message = options.message || '';
        const btnText = options.btnText || 'Got it';
        const type = options.type || 'info'; // 'info', 'success', 'error', 'warning'

        const colors = {
            info: 'blue',
            success: 'green',
            error: 'red',
            warning: 'amber'
        };
        const color = colors[type] || 'blue';

        const icons = {
            info: 'bi-info-circle-fill',
            success: 'bi-check-circle-fill',
            error: 'bi-x-circle-fill',
            warning: 'bi-exclamation-triangle-fill'
        };
        const icon = icons[type] || 'bi-info-circle-fill';

        const modalHtml = `
        <div id="customAlertModal" class="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center animate-fade-in p-4">
            <div class="bg-white dark:bg-dark-card rounded-3xl shadow-2xl max-w-sm w-full overflow-hidden transform scale-100 animate-fade-in-up border border-gray-100 dark:border-dark-border">
                <div class="p-8 text-center">
                    <div class="w-20 h-20 rounded-full bg-${color}-50 dark:bg-${color}-900/20 flex items-center justify-center mx-auto mb-6 shadow-inner">
                        <i class="bi ${icon} text-${color}-600 dark:text-${color}-400 text-4xl"></i>
                    </div>
                    <h3 class="text-2xl font-black text-gray-900 dark:text-white mb-3">${title}</h3>
                    <p class="text-gray-500 dark:text-dark-muted font-medium mb-8 leading-relaxed">${message}</p>
                    <button id="alertOkBtn" class="w-full py-4 bg-${color}-600 hover:bg-${color}-700 text-white rounded-2xl font-black shadow-xl shadow-${color}-500/30 transition-all active:scale-95">
                        ${btnText}
                    </button>
                </div>
            </div>
        </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        document.body.style.overflow = 'hidden';

        document.getElementById('alertOkBtn').onclick = function () {
            const modal = document.getElementById('customAlertModal');
            if (modal) modal.remove();
            document.body.style.overflow = '';
            resolve();
        };

        // Close on clicking overlay
        document.getElementById('customAlertModal').onclick = function (e) {
            if (e.target === this) {
                this.remove();
                document.body.style.overflow = '';
                resolve();
            }
        };
    });
};

async function showSection(sectionId) {
    if (window.event) {
        window.event.preventDefault();
    }

    const scrollContainer = document.getElementById('main-scroll-container');

    // If clicking the current active section
    if (window.activeSection === sectionId) {
        // If we are in a sub-view (meaning current view is not the main list),
        // we should continue and re-render the main section content
        if (!window.isSubView) {
            // Already at the root of the section, just scroll to top
            if (scrollContainer) {
                scrollContainer.scrollTo({ top: 0, behavior: 'smooth' });
            }

            // Also close sidebar on mobile if the function is available
            if (typeof window.closeMobileSidebar === 'function') {
                window.closeMobileSidebar();
            }
            return;
        }
        // If isSubView is true, we fall through to let the normal section rendering happen
    }

    // Check for unsaved changes
    if (window.isDirty) {
        showUnsavedChangesModal(async () => {
            window.isDirty = false;
            await showSection(sectionId);
        });
        return;
    }

    window.activeSection = sectionId;
    // Check access permissions
    if (!checkAccess(sectionId)) {
        showNotification('You do not have permission to access this section.', 'error');
        return;
    }

    const contentArea = document.getElementById('content-area');
    const pageTitle = document.getElementById('page-title');
    const breadcrumbCurrent = document.getElementById('breadcrumb-current') || { textContent: '' };

    // Update active state in sidebar
    document.querySelectorAll('.nav-item').forEach(item => {
        item.classList.remove('active');
        if (item.getAttribute('data-section') === sectionId) {
            item.classList.add('active');
        }
    });

    // Close mobile sidebar if function exists
    if (typeof window.closeMobileSidebar === 'function') {
        window.closeMobileSidebar();
    }

    contentArea.style.opacity = '1';
    window.isSubView = false;

    // Render content based on sectionId
    switch (sectionId) {
        case 'dashboard':
            renderDashboard();
            pageTitle.textContent = 'Dashboard';
            breadcrumbCurrent.textContent = 'Dashboard';
            break;
        case 'calendar':
            await fetchSessions();
            window.renderCalendar();
            pageTitle.textContent = 'Calendar';
            breadcrumbCurrent.textContent = 'Calendar';
            break;
        case 'sessions':
            await window.renderSessions();
            pageTitle.textContent = 'Sessions';
            breadcrumbCurrent.textContent = 'Sessions';
            break;
        case 'agendas':
            await window.renderAgendas();
            pageTitle.textContent = 'Agendas';
            breadcrumbCurrent.textContent = 'Agendas';
            break;
        case 'deadlines':
            renderDeadlines();
            pageTitle.textContent = 'Deadlines';
            breadcrumbCurrent.textContent = 'Deadlines';
            break;
        case 'reminders':
            renderReminders();
            pageTitle.textContent = 'Reminders';
            breadcrumbCurrent.textContent = 'Reminders';
            break;

        case 'users':
            renderUserManagement();
            pageTitle.textContent = 'User Management';
            breadcrumbCurrent.textContent = 'User Management';
            break;
        case 'analytics':
            renderReportsAnalytics();
            pageTitle.textContent = 'Reports & Analytics';
            breadcrumbCurrent.textContent = 'Reports & Analytics';
            break;
        case 'audit':
            renderAuditLogs();
            pageTitle.textContent = 'Audit Logs';
            breadcrumbCurrent.textContent = 'Audit Logs';
            break;
        case 'settings':
            await renderSettings();
            pageTitle.textContent = 'Settings';
            breadcrumbCurrent.textContent = 'Settings';
            break;
        case 'public-portal':
            if (getCurrentUser() && (getCurrentUser().role === 'Super Admin' || getCurrentUser().role === 'Admin' || getCurrentUser().role === 'Administrator')) {
                renderPortalManagement();
                pageTitle.textContent = 'Portal Management';
                breadcrumbCurrent.textContent = 'Portal Management';
            } else {
                renderPublicPortal();
            }
            break;
        case 'profile':
            renderProfile();
            pageTitle.textContent = 'My Profile';
            breadcrumbCurrent.textContent = 'My Profile';
            break;
        case 'documents':
            renderDocuments();
            pageTitle.textContent = 'Documents';
            breadcrumbCurrent.textContent = 'Documents';
            break;
        case 'announcements':
            renderAnnouncements();
            pageTitle.textContent = 'Announcements';
            breadcrumbCurrent.textContent = 'Announcements';
            break;
        case 'about-us':
            renderAboutUs();
            pageTitle.textContent = 'About Us';
            breadcrumbCurrent.textContent = 'About Us';
            break;
        case 'my-deadlines':
            renderMyDeadlines();
            pageTitle.textContent = 'My Deadlines';
            breadcrumbCurrent.textContent = 'My Deadlines';
            break;
        case 'notifications':
            if (typeof renderAllNotifications === 'function') {
                renderAllNotifications();
            } else {
                renderReminders();
            }
            break;
        case 'home':
            renderPublicPortal();
            return;
    }

    // Scroll to top of the content area
    if (scrollContainer) {
        scrollContainer.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
}

// Check if current user has access to the section
function checkAccess(sectionId) {
    const user = getCurrentUser();
    const role = user ? user.role : 'Super Admin';

    // Define permissions
    const permissions = {
        'Super Admin': ['dashboard', 'calendar', 'sessions', 'agendas', 'deadlines', 'reminders', 'notifications', 'users', 'analytics', 'audit', 'settings', 'public-portal', 'profile'],
        'Admin': ['dashboard', 'calendar', 'sessions', 'agendas', 'deadlines', 'reminders', 'notifications', 'users', 'analytics', 'public-portal', 'profile'],
        'Administrator': ['dashboard', 'calendar', 'sessions', 'agendas', 'deadlines', 'reminders', 'notifications', 'users', 'analytics', 'audit', 'settings', 'public-portal', 'profile'],
        'Staff': ['dashboard', 'calendar', 'sessions', 'agendas', 'deadlines', 'notifications', 'profile', 'analytics'],
        'User - Committee': ['dashboard', 'calendar', 'sessions', 'agendas', 'deadlines', 'notifications', 'profile', 'analytics']
    };

    // Allow access if role not defined (fallback) or if section is allowed
    if (!permissions[role]) return true;

    return permissions[role].includes(sectionId);
}

