function renderDashboard() {
    const user = getCurrentUser();
    const role = user ? user.role : 'Super Admin';

    const normalizedRole = role.toLowerCase();

    if (normalizedRole === 'super admin' || normalizedRole === 'admin' || normalizedRole === 'administrator') {
        renderAdminDashboard(user);
    } else if (normalizedRole === 'staff') {
        window.renderStaffDashboard(user);
    } else if (normalizedRole === 'user') {
        window.renderUserDashboard(user);
    } else {
        // Fallback for other roles or public
        document.getElementById('content-area').innerHTML = `
            <div class="p-8 text-center">
                <h2 class="text-2xl font-bold text-gray-800">Welcome to LACS</h2>
                <p class="text-gray-600 mt-2">Please select a module from the menu to get started.</p>
            </div>
        `;
    }
}

