// Filter sessions function
function filterSessions() {
    const searchTerm = document.getElementById('session-search')?.value.toLowerCase() || '';
    const typeFilter = document.getElementById('session-type-filter')?.value || 'all';
    const statusFilter = document.getElementById('session-status-filter')?.value || 'all';
    const user = getCurrentUser();
    const role = user ? user.role : 'User';

    let filtered = sessions.filter(session => {
        const matchesSearch = session.title.toLowerCase().includes(searchTerm) ||
            session.venue.toLowerCase().includes(searchTerm);
        const matchesType = typeFilter === 'all' || session.type === typeFilter;
        const matchesStatus = statusFilter === 'all' || session.status === statusFilter;

        return matchesSearch && matchesType && matchesStatus;
    });

    // Temporarily replace sessions array for rendering
    const originalSessions = sessions;
    sessions = filtered;

    const grid = document.getElementById('sessions-grid');
    if (grid) {
        grid.innerHTML = generateSessionCards(role);
    }

    // Restore original sessions array
    sessions = originalSessions;
}

// Helper to generate session cards based on role
function generateSessionCards(role) {
    const normalizedRole = role.toLowerCase();
    const isAdmin = (normalizedRole === 'super admin' || normalizedRole === 'admin');
    const isStaff = normalizedRole === 'staff';
    const isUser = normalizedRole === 'user';

    // Use global sessions variable
    // const sessions = [...]; // Removed local definition

    let html = '';

    // If no sessions, return empty message
    if (!sessions || sessions.length === 0) {
        return '<div class="bg-white p-12 rounded-xl shadow-sm border border-gray-100 text-center"><p class="text-gray-600">No sessions found in database.</p></div>';
    }

    sessions.forEach(session => {
        // Map session types - handle both "Regular Session" and "Regular"
        const sessionType = session.type || session.session_type || '';
        const typeShort = sessionType.includes('Regular') ? 'Regular' :
            sessionType.includes('Special') ? 'Special' :
                sessionType.includes('Emergency') ? 'Emergency' : sessionType;

        const typeColors = {
            'Regular': 'bg-blue-100 text-blue-800',
            'Regular Session': 'bg-blue-100 text-blue-800',
            'Special': 'bg-yellow-100 text-yellow-800',
            'Special Session': 'bg-yellow-100 text-yellow-800',
            'Emergency': 'bg-red-100 text-red-800',
            'Emergency Session': 'bg-red-100 text-red-800'
        };

        const statusColors = {
            'Scheduled': 'bg-green-100 text-green-800',
            'Ongoing': 'bg-blue-100 text-blue-800',
            'Completed': 'bg-gray-100 text-gray-800',
            'Cancelled': 'bg-red-100 text-red-800'
        };

        // For User role, don't show internal status or attendee count
        const showStatus = !isUser;
        const showAttendees = isAdmin;
        const showActions = !isUser;

        html += `
            <div class="bg-white p-6 rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition animate-fade-in-up">
                <div class="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div class="flex-1">
                        <div class="flex items-center gap-3 mb-2">
                            <span class="px-2.5 py-0.5 rounded-full text-xs font-medium ${typeColors[sessionType] || typeColors[typeShort] || 'bg-gray-100 text-gray-800'}">
                                ${sessionType}
                            </span>
                            ${showStatus ? `
                            <span class="px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColors[session.status]}">
                                ${session.status}
                            </span>
                            ` : ''}
                            ${isUser && (sessionType.includes('Regular') || typeShort === 'Regular') ? `
                            <span class="px-2.5 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-800">
                                Public Hearing
                            </span>
                            ` : ''}
                        </div>
                        <h3 class="text-lg font-bold text-gray-900 mb-1">${session.title}</h3>
                        <div class="flex flex-wrap items-center gap-4 text-sm text-gray-500">
                            <div class="flex items-center gap-1">
                                <i class="bi bi-calendar3"></i>
                                ${session.date}
                            </div>
                            <div class="flex items-center gap-1">
                                <i class="bi bi-clock"></i>
                                ${session.time}
                            </div>
                            <div class="flex items-center gap-1">
                                <i class="bi bi-geo-alt"></i>
                                ${session.venue}
                            </div>
                        </div>
                    </div>

                    <div class="flex items-center gap-4">
                        ${showAttendees ? `
                        <div class="text-right hidden md:block">
                            <p class="text-xs text-gray-500 uppercase font-semibold">Confirmed</p>
                            <p class="text-sm font-bold text-gray-800">${session.attendees}</p>
                        </div>
                        ` : ''}

                        ${isStaff && session.isAttending ? `
                        <div class="flex items-center gap-1 text-green-600 bg-green-50 px-3 py-1 rounded-full text-xs font-medium">
                            <i class="bi bi-check-circle-fill"></i> Attending
                        </div>
                        ` : ''}

                        <div class="flex items-center gap-2">
                            <button onclick="openSessionDetails(${session.id}, '${role}')" class="px-4 py-2 bg-white border border-gray-200 text-gray-700 hover:bg-gray-50 rounded-lg transition text-sm font-medium shadow-sm">
                                View Details
                            </button>
                            ${(isAdmin || isStaff) ? `
                            <button onclick="openEditSessionModal(${session.id})" class="p-2 text-gray-400 hover:text-red-600 transition" title="Edit Session">
                                <i class="bi bi-pencil"></i>
                            </button>
                            ` : ''}
                            ${(isAdmin || (isStaff && session.created_by == (getCurrentUser()?.id))) ? `
                            <button onclick="deleteSession(${session.id})" class="p-2 text-gray-400 hover:text-red-600 transition" title="Delete Session">
                                <i class="bi bi-x-circle"></i>
                            </button>
                            ` : ''}
                        </div>
                    </div>
                </div>
            </div>
            `;
    });
    return html;
}

