async function renderAgendaDetails(id) {
    // Show loading state
    document.getElementById('content-area').innerHTML = `
        <div class="flex items-center justify-center py-12">
            <div class="text-center">
                <div class="spinner mx-auto mb-4"></div>
                <p class="text-gray-600">Loading agenda details...</p>
            </div>
        </div>
    `;

    try {
        const response = await fetch(`api_agendas.php?id=${id}`);
        const data = await response.json();

        if (!data.success || !data.agenda) {
            showNotification('Agenda not found', 'error');
            renderAgendas();
            return;
        }

        const agenda = data.agenda;

        // Ensure items array exists
        if (!agenda.items) {
            agenda.items = [];
        }

        // Add/update agenda in the global agendas array for item management
        const existingIndex = agendas.findIndex(a => a.id === agenda.id);
        if (existingIndex >= 0) {
            agendas[existingIndex] = agenda;
        } else {
            agendas.push(agenda);
        }

        const user = getCurrentUser();
        const role = user ? user.role : 'User';
        const isAdmin = (role === 'Super Admin' || role === 'Admin' || role === 'Administrator');

        const html = `
            <div class="space-y-6 animate-fade-in-up">
            <!--Header-->
            <div class="flex items-center gap-2 text-sm text-gray-500 mb-2">
                <button onclick="renderAgendas()" class="hover:text-red-600 transition">Agendas</button>
                <i class="bi bi-chevron-right text-xs"></i>
                <span class="text-gray-800 font-medium">Agenda Details</span>
            </div>

            <div class="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 class="text-2xl font-bold text-gray-900">${agenda.title || `Agenda - ${agenda.sessionDate || 'N/A'} ${agenda.type || ''} Session`}</h1>
                    <p class="text-gray-500 mt-1">
                        <i class="bi bi-calendar3 mr-1"></i> ${agenda.sessionDate || 'N/A'}
                    </p>
                </div>
                <div class="flex gap-2">
                    ${isAdmin ? `
                        <button onclick="publishAgenda(${agenda.id})" class="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition shadow-sm flex items-center gap-2">
                            <i class="bi bi-check-circle"></i> Publish
                        </button>
                        <button onclick="openAgendaItemModal(${agenda.id})" class="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition shadow-sm flex items-center gap-2">
                            <i class="bi bi-plus-lg"></i> Add Item
                        </button>
                    ` : ''}
                </div>
            </div>

            <!--Agenda Items-->
            <div class="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div class="p-4 border-b border-gray-100 bg-gray-50 flex justify-between items-center">
                    <h3 class="font-bold text-gray-800">Order of Business</h3>
                    <span class="text-sm text-gray-500">${agenda.items.length} Items</span>
                </div>
                <div class="divide-y divide-gray-100" id="agendaItemsList">
                    ${agenda.items.map((item, index) => `
                        <div class="p-4 hover:bg-gray-50 transition group flex items-center gap-4" 
                             ${isAdmin ? `draggable="true" ondragstart="handleDragStart(event, ${index})" ondragover="handleDragOver(event)" ondrop="handleDrop(event, ${index}, ${agenda.id})"` : ''}>
                            <div class="flex-shrink-0 w-10 h-10 bg-red-600 text-white rounded-full flex items-center justify-center font-bold text-base">
                                ${index + 1}
                            </div>
                            <div class="flex-1 min-w-0">
                                <h4 class="text-base font-bold text-gray-900 mb-0.5">${item.title || 'Untitled Item'}</h4>
                                <p class="text-sm text-gray-600 mb-1">${item.type || item.title || ''}</p>
                                ${isAdmin ? `
                                    <button onclick="deleteAgendaItem(${agenda.id}, ${item.id})" class="text-red-600 text-sm hover:text-red-800 transition">
                                        Remove
                                    </button>
                                ` : ''}
                            </div>
                            ${isAdmin ? `
                                <div class="flex-shrink-0 text-gray-400 hover:text-gray-600 cursor-pointer">
                                    <i class="bi bi-three-dots-vertical text-lg"></i>
                                </div>
                            ` : ''}
                        </div>
                    `).join('')}
                    ${agenda.items.length === 0 ? `
                        <div class="p-8 text-center text-gray-500">
                            No items in this agenda yet.
                        </div>
                    ` : ''}
                </div>
            </div>
        </div>
            `;
        document.getElementById('content-area').innerHTML = html;
    } catch (error) {
        console.error('Error loading agenda:', error);
        showNotification('Failed to load agenda details', 'error');
        renderAgendas();
    }
}

