// Bulk actions for agendas
function bulkEditAgendas() {
    const selected = getSelectedAgendaIds();
    if (selected.length === 0) {
        showNotification('Please select at least one agenda', 'warning');
        return;
    }
    showNotification(`Edit functionality for ${selected.length} agenda(s) coming soon`, 'info');
}

function bulkCopyAgendas() {
    const selected = getSelectedAgendaIds();
    if (selected.length === 0) {
        showNotification('Please select at least one agenda', 'warning');
        return;
    }
    showNotification(`Copy functionality for ${selected.length} agenda(s) coming soon`, 'info');
}

async function bulkDeleteAgendas() {
    const selected = getSelectedAgendaIds();
    if (selected.length === 0) {
        showNotification('Please select at least one agenda', 'warning');
        return;
    }
    if (await confirm(`Are you sure you want to delete ${selected.length} agenda(s)?`)) {
        try {
            // Delete all selected agendas
            const deletePromises = selected.map(id => deleteAgenda(id, true)); // Pass true to skip confirmation for bulk delete
            await Promise.all(deletePromises);
            showNotification(`${selected.length} agenda(s) deleted successfully`, 'success');
            // Uncheck all checkboxes
            const checkAll = document.getElementById('checkAllAgendas');
            if (checkAll) checkAll.checked = false;
            // Refresh the view
            const contentArea = document.getElementById('content-area');
            if (contentArea && contentArea.innerHTML.includes('Session Agendas')) {
                // Extract sessionId from the current view
                const sessionIdMatch = contentArea.innerHTML.match(/viewSessionAgendas\((\d+)\)/);
                if (sessionIdMatch) {
                    await viewSessionAgendas(parseInt(sessionIdMatch[1]));
                } else {
                    renderAgendas();
                }
            } else {
                renderAgendas();
            }
        } catch (error) {
            console.error('Error in bulk delete:', error);
            showNotification('An error occurred during bulk delete', 'error');
        }
    }
}

function getSelectedAgendaIds() {
    const checkboxes = document.querySelectorAll('.agenda-checkbox:checked');
    return Array.from(checkboxes).map(cb => parseInt(cb.value));
}
function publishAgenda(id) {
    const agenda = agendas.find(a => a.id === id);
    if (agenda) {
        agenda.status = 'Published';
        showNotification('Agenda published', 'success');
        renderAgendaDetails(id);
    }
}

async function deleteAgenda(id, skipConfirmation = false) {
    if (!skipConfirmation && !confirm('Are you sure you want to delete this agenda? This action cannot be undone.')) {
        return;
    }

    try {
        const response = await fetch('../api/api_agendas.php', {
            method: 'DELETE',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                agenda_id: id
            })
        });

        const data = await response.json();

        if (data.success) {
            if (!skipConfirmation) {
                showNotification('Agenda deleted successfully', 'success');
            }
            // Only refresh if not in bulk delete mode
            if (!skipConfirmation) {
                // Check if we're viewing session agendas or main agendas page
                const contentArea = document.getElementById('content-area');
                if (contentArea && contentArea.innerHTML.includes('Session Agendas')) {
                    // Find the session ID from the page
                    const sessionIdMatch = contentArea.innerHTML.match(/viewSessionAgendas\((\d+)\)/);
                    if (sessionIdMatch) {
                        await viewSessionAgendas(parseInt(sessionIdMatch[1]));
                    } else {
                        renderAgendas();
                    }
                } else {
                    renderAgendas();
                }
            }
        } else {
            if (!skipConfirmation) {
                showNotification(data.message || 'Failed to delete agenda', 'error');
            }
        }
    } catch (error) {
        console.error('Error deleting agenda:', error);
        if (!skipConfirmation) {
            showNotification('An error occurred. Please try again.', 'error');
        }
    }
}

function deleteAgendaItem(agendaId, itemId) {
    const agenda = agendas.find(a => a.id === agendaId);
    if (agenda && confirm('Remove this item?')) {
        agenda.items = agenda.items.filter(i => i.id !== itemId);
        showNotification('Item removed', 'success');
        addAuditLog('DELETE_ITEM', `Removed item ${itemId} from agenda ${agendaId} `);
        renderAgendaDetails(agendaId);
    }
}

// Drag and Drop Handlers
let draggedItemIndex = null;

function handleDragStart(e, index) {
    draggedItemIndex = index;
    e.dataTransfer.effectAllowed = 'move';
    e.target.classList.add('opacity-50');
}

function handleDragOver(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
}

function handleDrop(e, index, agendaId) {
    e.preventDefault();
    const agenda = agendas.find(a => a.id === agendaId);
    if (!agenda || draggedItemIndex === null) return;

    // Reorder items
    const item = agenda.items.splice(draggedItemIndex, 1)[0];
    agenda.items.splice(index, 0, item);

    // Update numbers
    agenda.items.forEach((item, idx) => {
        item.number = idx + 1;
    });

    renderAgendaDetails(agendaId);
    addAuditLog('REORDER_ITEMS', `Reordered items in agenda ${agendaId} `);
}

