function execCmd(command) {
    document.execCommand(command, false, null);
}

function saveAgendaItem() {
    const agendaId = parseInt(document.getElementById('targetAgendaId').value);
    const title = document.getElementById('itemTitle').value;
    const type = document.getElementById('itemType').value;
    const assignee = document.getElementById('itemAssignee').value;
    const description = document.getElementById('itemDescription').innerHTML;
    const internalNotes = document.getElementById('itemInternalNotes').value;

    if (!title) {
        showNotification('Please enter an item title', 'error');
        return;
    }

    const agenda = agendas.find(a => a.id === agendaId);
    if (agenda) {
        const newItem = {
            id: Date.now(), // Simple ID generation
            number: agenda.items.length + 1,
            type: type,
            title: title,
            description: description,
            status: 'Pending',
            assignedTo: assignee || 'Unassigned',
            internalNotes: internalNotes
        };

        agenda.items.push(newItem);
        showNotification('Item added successfully', 'success');
        addAuditLog('ADD_ITEM', `Added item ${title} to agenda ${agendaId}`);
        document.getElementById('agendaItemModal').remove();
        renderAgendaDetails(agendaId);
    }
}

