function renderNotificationList(items, isStaff = false) {
    if (items.length === 0) {
        return `
            <div class="p-12 text-center text-gray-500">
                <i class="bi bi-bell-slash text-4xl mb-3 block"></i>
                <p>No notifications found.</p>
            </div>
        `;
    }

    return `
        <div class="divide-y divide-gray-100">
            ${items.map(item => `
                <div class="p-4 hover:bg-gray-50 transition group ${item.status === 'Unread' ? 'bg-red-50/30' : ''}">
                    <div class="flex gap-4">
                        <div class="flex-shrink-0">
                            ${getNotificationIcon(item.type)}
                        </div>
                        <div class="flex-1 min-w-0">
                            <div class="flex justify-between items-start mb-1">
                                <div class="flex items-center gap-2">
                                    <span class="text-xs font-bold px-2 py-0.5 rounded border ${getNotificationTypeColor(item.type)}">
                                        ${item.type}
                                    </span>
                                    ${getPriorityBadge(item.priority)}
                                    <span class="text-xs text-gray-500">• ${item.timestamp}</span>
                                </div>
                                ${item.status === 'Unread' ? '<span class="w-2 h-2 bg-red-600 rounded-full"></span>' : ''}
                            </div>
                            <h4 class="text-base font-bold text-gray-900 mb-1 ${item.status === 'Unread' ? '' : 'font-medium'}">
                                ${item.subject}
                            </h4>
                            <p class="text-sm text-gray-600 mb-3 line-clamp-2">${item.message}</p>
                            
                            <div class="flex items-center gap-3">
                                ${item.relatedId ? `
                                    <button class="text-xs font-medium text-red-600 hover:text-red-700 flex items-center gap-1">
                                        View Details <i class="bi bi-arrow-right"></i>
                                    </button>
                                ` : ''}
                                ${!isStaff ? `
                                    <button class="text-xs text-gray-500 hover:text-gray-700">Resend</button>
                                    <button class="text-xs text-gray-500 hover:text-gray-700">Delete</button>
                                ` : ''}
                                ${isStaff && item.status === 'Unread' ? `
                                    <button onclick="markAsRead(${item.id})" class="text-xs text-gray-500 hover:text-gray-700">Mark as Read</button>
                                ` : ''}
                            </div>
                        </div>
                    </div>
                </div>
            `).join('')}
        </div>
    `;
}

function getNotificationIcon(type) {
    const icons = {
        'Session Reminder': '<div class="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center"><i class="bi bi-calendar-event"></i></div>',
        'Deadline Alert': '<div class="w-10 h-10 rounded-full bg-red-100 text-red-600 flex items-center justify-center"><i class="bi bi-alarm"></i></div>',
        'Agenda Notification': '<div class="w-10 h-10 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center"><i class="bi bi-journal-text"></i></div>',
        'System Alert': '<div class="w-10 h-10 rounded-full bg-yellow-100 text-yellow-600 flex items-center justify-center"><i class="bi bi-exclamation-triangle"></i></div>',
        'Manual Reminder': '<div class="w-10 h-10 rounded-full bg-gray-100 text-gray-600 flex items-center justify-center"><i class="bi bi-envelope"></i></div>'
    };
    return icons[type] || icons['Manual Reminder'];
}

function getNotificationTypeColor(type) {
    const colors = {
        'Session Reminder': 'bg-blue-50 text-blue-700 border-blue-200',
        'Deadline Alert': 'bg-red-50 text-red-700 border-red-200',
        'Agenda Notification': 'bg-purple-50 text-purple-700 border-purple-200',
        'System Alert': 'bg-yellow-50 text-yellow-700 border-yellow-200',
        'Manual Reminder': 'bg-gray-50 text-gray-700 border-gray-200'
    };
    return colors[type] || colors['Manual Reminder'];
}

function getPriorityBadge(priority) {
    const badges = {
        'High': '<span class="text-xs font-medium text-red-600 bg-red-50 px-1.5 py-0.5 rounded">High Priority</span>',
        'Medium': '<span class="text-xs font-medium text-yellow-600 bg-yellow-50 px-1.5 py-0.5 rounded">Medium</span>',
        'Low': '<span class="text-xs font-medium text-gray-600 bg-gray-50 px-1.5 py-0.5 rounded">Low</span>'
    };
    return badges[priority] || badges['Low'];
}

function switchReminderTab(tab) {
    // Update tab styles
    document.querySelectorAll('[id^="tab-"]').forEach(el => {
        el.className = 'px-6 py-4 text-sm font-medium text-gray-500 hover:text-gray-700 whitespace-nowrap';
        el.classList.remove('text-red-600', 'border-b-2', 'border-red-600');
    });
    const activeTab = document.getElementById(`tab-${tab}`);
    activeTab.className = 'px-6 py-4 text-sm font-medium text-red-600 border-b-2 border-red-600 whitespace-nowrap';

    // Update content
    const contentDiv = document.getElementById('reminderContent');
    const filtersDiv = document.getElementById('reminderFilters');

    if (tab === 'settings') {
        filtersDiv.classList.add('hidden');
        contentDiv.innerHTML = renderReminderSettingsForm();
    } else {
        filtersDiv.classList.remove('hidden');
        let filteredItems = notifications;
        if (tab === 'unread') filteredItems = notifications.filter(n => n.status === 'Unread');
        if (tab === 'sent') filteredItems = notifications.filter(n => n.sender === 'Admin User'); // Mock logic
        if (tab === 'scheduled') filteredItems = []; // Mock empty scheduled

        contentDiv.innerHTML = renderNotificationList(filteredItems);
    }
}

function switchStaffTab(tab) {
    // Update tab styles
    document.querySelectorAll('[id^="staff-tab-"]').forEach(el => {
        el.className = 'px-6 py-4 text-sm font-medium text-gray-500 hover:text-gray-700 whitespace-nowrap';
        el.classList.remove('text-red-600', 'border-b-2', 'border-red-600');
    });
    const activeTab = document.getElementById(`staff-tab-${tab}`);
    activeTab.className = 'px-6 py-4 text-sm font-medium text-red-600 border-b-2 border-red-600 whitespace-nowrap';

    // Update content
    const contentDiv = document.getElementById('staffReminderContent');

    if (tab === 'settings') {
        contentDiv.innerHTML = renderStaffSettingsForm();
    } else {
        let filteredItems = notifications;
        if (tab === 'unread') filteredItems = notifications.filter(n => n.status === 'Unread');
        contentDiv.innerHTML = renderNotificationList(filteredItems, true);
    }
}

