async function renderAuditLogs() {
    try {
        const response = await fetch('../api/api_logs.php');
        const data = await response.json();

        if (!data.success) {
            showNotification('Failed to load audit logs', 'error');
            return;
        }

        const logs = data.logs || [];
        const criticalCount = logs.filter(l => l.severity === 'Critical' || l.action.toLowerCase().includes('delete') || l.action.toLowerCase().includes('fail')).length;
        const securityActions = logs.filter(l => l.action.toLowerCase().includes('auth') || l.action.toLowerCase().includes('login') || l.action.toLowerCase().includes('password')).length;

        const html = `
        <div class="space-y-6 animate-fade-in-up pb-10">
            <!-- Premium Header Banner -->
            <div class="relative overflow-hidden rounded-2xl bg-gradient-to-br from-red-600 via-red-700 to-red-800 p-8 shadow-xl mb-6">
                <div class="absolute inset-0 bg-black opacity-10"></div>
                <div class="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-32 -mt-32"></div>
                <div class="absolute bottom-0 left-0 w-48 h-48 bg-white opacity-5 rounded-full -ml-24 -mb-24"></div>
                
                <div class="relative z-10">
                    <div class="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                        <div class="text-white">
                            <h1 class="text-3xl font-bold mb-2">System Audit Logs</h1>
                            <p class="text-red-100 text-sm opacity-90">Monitor system activities, security events, and administrative changes</p>
                        </div>
                        <div class="flex gap-3">
                            <button onclick="renderAuditLogs()" class="px-5 py-2.5 bg-white/10 text-white rounded-xl hover:bg-white/20 text-sm font-bold flex items-center gap-2 border border-white/20 transition-all">
                                <i class="bi bi-arrow-clockwise"></i> Refresh Logs
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Stats Grid -->
            <div class="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                <div class="group bg-gradient-to-br from-red-50 to-white p-6 rounded-2xl shadow-sm border border-red-100 hover:shadow-md transition-all">
                    <div class="flex justify-between items-start">
                        <div>
                            <p class="text-sm font-medium text-red-600 mb-1 uppercase tracking-wider">Total Activities</p>
                            <h3 class="text-3xl font-bold text-gray-900">${logs.length}</h3>
                        </div>
                        <div class="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-red-600 border border-gray-200 group-hover:scale-110 transition-transform">
                            <i class="bi bi-activity text-xl"></i>
                        </div>
                    </div>
                </div>
                
                <div class="group bg-gradient-to-br from-amber-50 to-white p-6 rounded-2xl shadow-sm border border-amber-100 hover:shadow-md transition-all">
                    <div class="flex justify-between items-start">
                        <div>
                            <p class="text-sm font-medium text-amber-600 mb-1 uppercase tracking-wider">Critical Events</p>
                            <h3 class="text-3xl font-bold text-gray-900">${criticalCount}</h3>
                        </div>
                        <div class="w-12 h-12 bg-amber-100 rounded-xl flex items-center justify-center text-amber-600 group-hover:scale-110 transition-transform">
                            <i class="bi bi-exclamation-triangle text-xl"></i>
                        </div>
                    </div>
                </div>

                <div class="group bg-gradient-to-br from-blue-50 to-white p-6 rounded-2xl shadow-sm border border-blue-100 hover:shadow-md transition-all">
                    <div class="flex justify-between items-start">
                        <div>
                            <p class="text-sm font-medium text-blue-600 mb-1 uppercase tracking-wider">Security Tasks</p>
                            <h3 class="text-3xl font-bold text-gray-900">${securityActions}</h3>
                        </div>
                        <div class="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center text-blue-600 group-hover:scale-110 transition-transform">
                            <i class="bi bi-shield-lock text-xl"></i>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Filters & Search -->
            <div class="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-wrap gap-4 items-center">
                <div class="relative flex-1 min-w-[300px]">
                    <i class="bi bi-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                    <input type="text" id="logSearch" onkeyup="filterAuditLogs()" placeholder="Search logs by action, user, or details..." 
                        class="w-full pl-11 pr-4 py-3 bg-gray-50 border-0 rounded-xl focus:ring-2 focus:ring-red-500 transition-all outline-none text-sm">
                </div>
                <select id="logActionFilter" onchange="filterAuditLogs()" class="px-4 py-3 bg-gray-50 border-0 rounded-xl focus:ring-2 focus:ring-red-500 transition-all outline-none text-sm font-medium text-gray-600">
                    <option value="">All Actions</option>
                    <option value="LOGIN">Auth/Login</option>
                    <option value="CREATE">Creation</option>
                    <option value="UPDATE">Updates</option>
                    <option value="DELETE">Deletions</option>
                </select>
            </div>

            <!-- Audit Table -->
            <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div class="overflow-x-auto">
                    <table class="w-full text-left border-collapse" id="auditLogsTable">
                        <thead class="bg-gray-50/80 text-xs uppercase text-gray-500 font-bold">
                            <tr>
                                <th class="p-4 pl-6">Timestamp</th>
                                <th class="p-4">User</th>
                                <th class="p-4">Action</th>
                                <th class="p-4">Details</th>
                                <th class="p-4 pr-6 text-right">Status</th>
                            </tr>
                        </thead>
                        <tbody class="divide-y divide-gray-100 text-sm">
                            ${logs.length > 0 ? logs.map(l => {
            const date = new Date(l.created_at);
            let statusClass = "bg-green-100 text-green-700";
            if (l.action.toLowerCase().includes('fail') || l.action.toLowerCase().includes('error')) statusClass = "bg-red-100 text-red-700 font-bold";
            if (l.action.toLowerCase().includes('delete')) statusClass = "bg-amber-100 text-amber-700";

            return `
                                <tr class="hover:bg-gray-50 transition group log-row" data-search="${l.user_name} ${l.action} ${l.description}">
                                    <td class="p-4 pl-6 text-gray-500 whitespace-nowrap">
                                        <div class="flex flex-col">
                                            <span class="font-bold text-gray-900">${date.toLocaleDateString()}</span>
                                            <span class="text-xs">${date.toLocaleTimeString()}</span>
                                        </div>
                                    </td>
                                    <td class="p-4 whitespace-nowrap">
                                        <div class="flex items-center gap-3">
                                            <div class="w-8 h-8 rounded-full bg-red-100 flex items-center justify-center text-red-600 font-bold text-xs">
                                                ${(l.user_name || 'S').charAt(0)}
                                            </div>
                                            <span class="font-bold text-gray-800">${l.user_name || 'System'}</span>
                                        </div>
                                    </td>
                                    <td class="p-4">
                                        <span class="font-medium text-gray-700">${l.action}</span>
                                    </td>
                                    <td class="p-4">
                                        <div class="text-gray-600 truncate max-w-md" title="${l.description}">${l.description || 'No additional details'}</div>
                                    </td>
                                    <td class="p-4 pr-6 text-right">
                                        <span class="px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusClass}">
                                            SUCCESS
                                        </span>
                                    </td>
                                </tr>
                                `;
        }).join('') : `
                            <tr>
                                <td colspan="5" class="p-12 text-center">
                                    <div class="flex flex-col items-center justify-center text-gray-400">
                                        <i class="bi bi-shield-slash text-5xl mb-4 opacity-20"></i>
                                        <p class="text-lg font-medium">No audit logs available</p>
                                    </div>
                                </td>
                            </tr>
                            `}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
        `;
        document.getElementById('content-area').innerHTML = html;
    } catch (e) {
        console.error('Audit Logs Error:', e);
        showNotification('Error rendering audit logs', 'error');
    }
}

function filterAuditLogs() {
    const search = document.getElementById('logSearch').value.toLowerCase();
    const actionFilter = document.getElementById('logActionFilter').value.toLowerCase();
    const rows = document.querySelectorAll('.log-row');

    rows.forEach(row => {
        const rowData = row.getAttribute('data-search').toLowerCase();
        const matchesSearch = rowData.includes(search);
        const matchesAction = actionFilter === "" || rowData.includes(actionFilter);

        if (matchesSearch && matchesAction) {
            row.style.display = "";
        } else {
            row.style.display = "none";
        }
    });
}

