function renderReportsAnalytics() {
    const user = getCurrentUser();
    const role = user ? user.role : 'Super Admin';

    if ((role === 'Super Admin' || role === 'Admin' || role === 'Administrator')) {
        renderAdminAnalytics(user);
    } else if (role === 'Staff') {
        renderStaffAnalytics(user);
    } else {
        document.getElementById('content-area').innerHTML = `
            <div class="p-8 text-center">
                <p class="text-red-500">Access Denied: You do not have permission to view this module.</p>
            </div>
        `;
    }
}

