function switchAnalyticsTab(tabName) {
    // Update Tabs UI
    const tabs = ['overview', 'builder', 'scheduled', 'saved'];
    tabs.forEach(t => {
        const el = document.getElementById(`tab-${t}`);
        if (el) {
            if (t === tabName) {
                el.classList.add('text-red-600', 'border-red-600', 'active');
                el.classList.remove('border-transparent');
            } else {
                el.classList.remove('text-red-600', 'border-red-600', 'active');
                el.classList.add('border-transparent');
            }
        }
    });

    const contentDiv = document.getElementById('analytics-content');
    contentDiv.style.opacity = '0';

    setTimeout(() => {
        switch (tabName) {
            case 'overview':
                contentDiv.innerHTML = getAnalyticsOverviewContent();
                setTimeout(renderAnalyticsCharts, 50);
                break;
            case 'builder':
                contentDiv.innerHTML = getAnalyticsBuilderContent();
                break;
            case 'scheduled':
                contentDiv.innerHTML = getAnalyticsScheduledContent();
                break;
            case 'saved':
                contentDiv.innerHTML = getAnalyticsSavedContent();
                break;
        }
        contentDiv.style.opacity = '1';
    }, 200);
}

