function renderAnalyticsCharts() {
    // Only render if charts exist in the DOM (Admin View)
    const sessionCtx = document.getElementById('sessionsChart');
    const activityCtx = document.getElementById('activityChart');

    if (!sessionCtx || !activityCtx) return;

    if (typeof Chart !== 'undefined') {
        // Destroy existing analytics charts if any (to prevent overlap on re-render)
        // Note: For a simpler implementation here, we assume fresh render or rely on Chart.js replacement behavior

        new Chart(sessionCtx, {
            type: 'doughnut',
            data: {
                labels: ['Regular', 'Special', 'Emergency', 'Committee Hearing'],
                datasets: [{
                    data: [12, 3, 1, 8],
                    backgroundColor: ['#dc2626', '#16a34a', '#dc2626', '#2563eb'],
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        position: 'right',
                        labels: {
                            usePointStyle: true,
                            boxWidth: 6
                        }
                    }
                }
            }
        });

        new Chart(activityCtx, {
            type: 'bar',
            data: {
                labels: ['Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'],
                datasets: [{
                    label: 'Documents Uploaded',
                    data: [65, 59, 80, 81, 56, 125],
                    backgroundColor: '#dc2626',
                    borderRadius: 4
                }, {
                    label: 'Sessions Held',
                    data: [4, 4, 5, 4, 3, 5],
                    backgroundColor: '#1f2937',
                    borderRadius: 4
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        beginAtZero: true
                    }
                }
            }
        });
    }
}

// DELETED LEGACY SETTINGS CODE

// DELETED LEGACY SETTINGS COMPONENT FUNCTIONS (REPLACED BY PREMIUM MODULE)

// ==============================
// PUBLIC PORTAL MODULE
// ==============================

// Global theme toggle function - accessible from both admin and public portal
window.toggleTheme = function () {
    const html = document.documentElement;
    if (html.classList.contains('dark')) {
        html.classList.remove('dark');
        localStorage.setItem('theme', 'light');
    } else {
        html.classList.add('dark');
        localStorage.setItem('theme', 'dark');
    }
    updateThemeIcons();
};

// Update theme icons function
window.updateThemeIcons = function () {
    const isDark = document.documentElement.classList.contains('dark');
    // Update admin side icons
    document.querySelectorAll('.dark-mode-icon').forEach(el => {
        el.classList.toggle('hidden', isDark);
    });
    document.querySelectorAll('.light-mode-icon').forEach(el => {
        el.classList.toggle('hidden', !isDark);
    });
    // Update public portal icons
    document.querySelectorAll('[data-theme-icon]').forEach(el => {
        const iconType = el.getAttribute('data-theme-icon');
        if (iconType === 'moon') {
            el.classList.toggle('hidden', isDark);
        } else if (iconType === 'sun') {
            el.classList.toggle('hidden', !isDark);
        }
    });
};

// Initialize theme on page load
window.initializeTheme = function () {
    if (localStorage.getItem('theme') === 'dark') {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
    updateThemeIcons();
};

// Update portal date/time display
window.updatePortalDateTime = function () {
    const dateEl = document.getElementById('portal-navbar-date');
    const timeEl = document.getElementById('portal-navbar-time');

    if (dateEl && timeEl) {
        const now = new Date();
        const dateOptions = { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' };
        const timeOptions = { hour: '2-digit', minute: '2-digit', second: '2-digit' };
        dateEl.textContent = now.toLocaleDateString(undefined, dateOptions);
        timeEl.textContent = now.toLocaleTimeString(undefined, timeOptions);
    }
};

