// --- Deadlines Management API Integration ---
async function renderDeadlines() {
    try {
        const response = await fetch('../api/api_deadlines.php');
        const data = await response.json();

        if (!data.success) {
            showNotification('Failed to load deadlines: ' + data.message, 'error');
            return;
        }

        const deadlines = data.deadlines || [];
        const totalActive = deadlines.filter(d => d.status !== 'Completed').length;
        const overdue = deadlines.filter(d => d.status === 'Overdue' || (new Date(d.due_date) < new Date() && d.status !== 'Completed')).length;
        const dueToday = deadlines.filter(d => new Date(d.due_date).toDateString() === new Date().toDateString()).length;
        const completionRate = deadlines.length > 0
            ? Math.round((deadlines.filter(d => d.status === 'Completed').length / deadlines.length) * 100)
            : 0;

        const html = `
        <div class="space-y-6 animate-fade-in-up">
            <!--Header-->
            <div class="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 class="text-2xl font-bold text-gray-800">Deadline Tracking</h2>
                </div>
                <div class="flex gap-2">
                    <button onclick="openCreateDeadlineModal()" class="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition flex items-center gap-2 shadow-sm">
                        <i class="bi bi-plus-lg"></i> Set Deadline
                    </button>
                    <button class="btn-outline">
                        <i class="bi bi-download mr-2"></i>Report
                    </button>
                </div>
            </div>

            <!--Stats Overview-->
            <div class="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div class="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <div class="flex justify-between items-start mb-2">
                        <div class="w-10 h-10 rounded-lg bg-blue-50 flex items-center justify-center text-blue-600">
                            <i class="bi bi-list-task text-xl"></i>
                        </div>
                        <span class="text-xs font-bold text-gray-400 uppercase">Active</span>
                    </div>
                    <h3 class="text-2xl font-bold text-gray-900">${totalActive}</h3>
                    <p class="text-xs text-gray-500">Tasks in progress</p>
                </div>
                <div class="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <div class="flex justify-between items-start mb-2">
                        <div class="w-10 h-10 rounded-lg bg-red-50 flex items-center justify-center text-red-600">
                            <i class="bi bi-exclamation-circle text-xl"></i>
                        </div>
                        <span class="text-xs font-bold text-gray-400 uppercase">Overdue</span>
                    </div>
                    <h3 class="text-2xl font-bold text-gray-900">${overdue}</h3>
                    <p class="text-xs text-gray-500">Requires attention</p>
                </div>
                <div class="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <div class="flex justify-between items-start mb-2">
                        <div class="w-10 h-10 rounded-lg bg-yellow-50 flex items-center justify-center text-yellow-600">
                            <i class="bi bi-calendar-event text-xl"></i>
                        </div>
                        <span class="text-xs font-bold text-gray-400 uppercase">Due Today</span>
                    </div>
                    <h3 class="text-2xl font-bold text-gray-900">${dueToday}</h3>
                    <p class="text-xs text-gray-500">Urgent deliverables</p>
                </div>
                <div class="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <div class="flex justify-between items-start mb-2">
                        <div class="w-10 h-10 rounded-lg bg-green-50 flex items-center justify-center text-green-600">
                            <i class="bi bi-check2-circle text-xl"></i>
                        </div>
                        <span class="text-xs font-bold text-gray-400 uppercase">Completion</span>
                    </div>
                    <h3 class="text-2xl font-bold text-gray-900">${completionRate}%</h3>
                    <p class="text-xs text-gray-500">Overall rate</p>
                </div>
            </div>

            <!--Filters-->
            <div class="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-center gap-4">
                 <div class="relative w-full md:w-96">
                    <i class="bi bi-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
                    <input type="text" placeholder="Search deadlines..." class="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500 text-sm">
                </div>
            </div>

            <!-- Content Area (List) -->
            <div class="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <table class="w-full text-left border-collapse">
                    <thead class="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                        <tr>
                            <th class="p-4">Task</th>
                            <th class="p-4">Due Date</th>
                            <th class="p-4">Status</th>
                            <th class="p-4">Priority</th>
                            <th class="p-4">Assigned To</th>
                            <th class="p-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-gray-100 text-sm">
                        ${deadlines.map(d => `
                        <tr class="hover:bg-gray-50 transition">
                            <td class="p-4 font-medium text-gray-900">${d.title}</td>
                            <td class="p-4 text-gray-600">${new Date(d.due_date).toLocaleDateString()}</td>
                            <td class="p-4">
                                <span class="badge ${d.status === 'Completed' ? 'badge-success' :
                d.status === 'Overdue' ? 'badge-error' :
                    d.status === 'In Progress' ? 'badge-info' : 'badge-warning'
            }">${d.status}</span>
                            </td>
                            <td class="p-4">
                                 <span class="text-xs font-bold ${d.priority === 'High' ? 'text-red-600' :
                d.priority === 'Medium' ? 'text-orange-600' : 'text-green-600'
            }">${d.priority}</span>
                            </td>
                            <td class="p-4 text-gray-600">${d.assigned_to_name || 'Unassigned'}</td>
                            <td class="p-4 text-right">
                                <button class="text-gray-400 hover:text-red-600"><i class="bi bi-trash"></i></button>
                            </td>
                        </tr>
                        `).join('')}
                    </tbody>
                </table>
                 ${deadlines.length === 0 ? '<div class="p-8 text-center text-gray-500">No deadlines found.</div>' : ''}
            </div>
        </div>
        `;
        document.getElementById('content-area').innerHTML = html;
    } catch (e) {
        console.error(e);
        showNotification('Error loading deadlines', 'error');
    }
}

