async function saveDeadline(event) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const data = Object.fromEntries(formData.entries());

    try {
        const response = await fetch('../api/api_deadlines.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Deadline created', 'success');
            document.getElementById('createDeadlineModal').remove();
            renderDeadlines();
        } else {
            showNotification(result.message, 'error');
        }
    } catch (e) {
        showNotification('Error saving deadline', 'error');
    }
}

