async function saveReminder(event) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const data = Object.fromEntries(formData.entries());

    try {
        const response = await fetch('../api/api_reminders.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Reminder set successfully', 'success');
            document.getElementById('createReminderModal').remove();
            renderReminders();
        } else {
            showNotification(result.message, 'error');
        }
    } catch (e) {
        showNotification('Error saving reminder', 'error');
    }
}

async function deleteReminder(id) {
    if (!await confirm('Are you sure?')) return;
    try {
        const response = await fetch('../api/api_reminders.php', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ reminder_id: id })
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Reminder deleted', 'success');
            renderReminders();
        }
    } catch (e) {
        showNotification('Error deleting reminder', 'error');
    }
}

