// Clear any existing error notifications when Reminders loads
function clearErrorNotifications() {
    // Remove any notification elements
    const notifications = document.querySelectorAll('[class*="notification"], [class*="alert"], [class*="toast"]');
    notifications.forEach(n => {
        if (n.textContent.includes('Error loading reminders')) {
            n.remove();
        }
    });

    // Also check for any fixed/absolute positioned error messages
    const errorElements = document.querySelectorAll('.fixed, .absolute');
    errorElements.forEach(el => {
        if (el.textContent.includes('Error loading reminders')) {
            el.remove();
        }
    });
}

// Override renderReminders to clear notifications first
const originalRenderReminders = renderReminders;
function renderReminders() {
    clearErrorNotifications();
    originalRenderReminders();
}

// Also clear on page load
document.addEventListener('DOMContentLoaded', function () {
    setTimeout(clearErrorNotifications, 100);
});

// Clear when navigating to reminders section
if (typeof showSection !== 'undefined') {
    const originalShowSection = showSection;
    window.showSection = function (section) {
        if (section === 'reminders') {
            clearErrorNotifications();
        }
        return originalShowSection(section);
    };
}

