window.openCreateReminderModalFinal = function () {
    const existing = document.getElementById('createReminderModal');
    if (existing) existing.remove();

    const now = new Date();
    // Set to today at 00:00:00 to allow any time but prevent past dates
    const minTime = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString().substring(0, 16);

    const modalHtml = `
        <div id="createReminderModal" class="fixed inset-0 bg-black bg-opacity-50 overflow-y-auto h-full w-full flex items-center justify-center z-50 backdrop-blur-sm">
            <div class="relative p-6 border w-full max-w-md shadow-2xl rounded-2xl bg-white animate-fade-in-up m-4">
                <div class="flex justify-between items-center mb-6">
                    <div>
                        <h3 class="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            <i class="bi bi-bell-fill text-red-600"></i>
                            Create Reminder
                        </h3>
                        <p class="text-sm text-gray-500 mt-1">Set a new reminder notification</p>
                    </div>
                    <button onclick="document.getElementById('createReminderModal').remove()" class="text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg p-2 transition">
                        <i class="bi bi-x-lg text-xl"></i>
                    </button>
                </div>
                <form onsubmit="saveReminderFinal(event)">
                    <div class="space-y-5">
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Title *</label>
                            <input type="text" name="title" required placeholder="e.g., Team Meeting" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent transition">
                        </div>
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Message</label>
                            <textarea name="message" rows="3" placeholder="Add additional details..." class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent transition resize-none"></textarea>
                        </div>
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Date & Time *</label>
                            <input type="datetime-local" name="reminder_date" required min="${minTime}" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent transition">
                        </div>
                        <div class="flex gap-3 pt-4">
                            <button type="button" onclick="document.getElementById('createReminderModal').remove()" class="flex-1 px-4 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 font-medium transition">
                                Cancel
                            </button>
                            <button type="submit" class="flex-1 px-4 py-3 bg-gradient-to-r from-red-600 to-red-700 text-white rounded-lg hover:from-red-700 hover:to-red-800 font-medium shadow-lg shadow-red-500/30 transition-all">
                                <i class="bi bi-check-lg mr-2"></i>Set Reminder
                            </button>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
};

window.saveReminderFinal = async function (event) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const data = Object.fromEntries(formData.entries());

    try {
        const response = await fetch('../api/api_reminders.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Reminder set successfully', 'success');
            document.getElementById('createReminderModal').remove();
            renderReminders();
        } else {
            showNotification(result.message || 'Failed to create reminder', 'error');
        }
    } catch (e) {
        console.error('Save error:', e);
        showNotification('Error saving reminder', 'error');
    }
};

window.deleteReminderFinal = async function (id) {
    if (!await confirm('Delete this reminder?')) return;

    const passwordOk = await window.promptPasswordConfirmation({
        title: 'Confirm Delete Reminder',
        message: 'Enter your password to delete this reminder.',
        confirmText: 'Confirm Delete'
    });
    if (!passwordOk) return;
    try {
        const response = await fetch('../api/api_reminders.php', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ reminder_id: id })
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Reminder deleted', 'success');
            renderReminders();
        } else {
            showNotification('Failed to delete reminder', 'error');
        }
    } catch (e) {
        console.error('Delete error:', e);
        showNotification('Error deleting reminder', 'error');
    }
};

