// Shared helper to load venues into a dropdown and attach address tooltip behavior
window.loadVenueDropdown = async function (selectId, tooltipId, addressTextId, selectedVenueId = null, selectedVenueName = null) {
    try {
        const selectEl = document.getElementById(selectId);
        if (!selectEl) return;

        const tooltip = tooltipId ? document.getElementById(tooltipId) : null;
        const addressText = addressTextId ? document.getElementById(addressTextId) : null;

        const resp = await fetch('../api/api_venues.php');
        const data = await resp.json();
        const venues = (data.success && Array.isArray(data.venues)) ? data.venues : [];

        let optionsHtml = '<option value=\"\">Select a venue...</option>';
        venues.forEach(v => {
            const isSelected =
                (selectedVenueId && parseInt(selectedVenueId) === parseInt(v.id)) ||
                (selectedVenueName && selectedVenueName === v.venue_name);
            optionsHtml += `<option value=\"${v.id}\" data-address=\"${v.address || ''}\" ${isSelected ? 'selected' : ''}>${v.venue_name}</option>`;
        });
        selectEl.innerHTML = optionsHtml;

        if (tooltip && addressText) {
            const updateTooltip = () => {
                const selectedOption = selectEl.options[selectEl.selectedIndex];
                const address = selectedOption ? selectedOption.getAttribute('data-address') : '';
                if (address && address.trim()) {
                    addressText.textContent = address;
                } else {
                    addressText.textContent = 'No address available';
                }
            };

            selectEl.addEventListener('mouseenter', () => {
                updateTooltip();
                tooltip.classList.remove('hidden');
            });

            selectEl.addEventListener('mouseleave', () => {
                tooltip.classList.add('hidden');
            });

            selectEl.addEventListener('change', () => {
                updateTooltip();
                tooltip.classList.remove('hidden');
                setTimeout(() => {
                    if (document.activeElement !== selectEl) {
                        tooltip.classList.add('hidden');
                    }
                }, 2000);
            });

            // Initialize tooltip content
            updateTooltip();
        }
    } catch (e) {
        console.error('Error loading venues for dropdown:', e);
    }
};

const SESSION_TITLE_BODY = 'Sangguniang Panlungsod ng Valenzuela';

function toOrdinalSuffix(number) {
    const n = parseInt(number, 10);
    if (!n || n <= 0) return '';
    if (![11, 12, 13].includes(n % 100)) {
        switch (n % 10) {
            case 1: return `${n}st`;
            case 2: return `${n}nd`;
            case 3: return `${n}rd`;
        }
    }
    return `${n}th`;
}

function buildSessionTitle(sessionNumber, sessionType, titleBody = SESSION_TITLE_BODY) {
    const n = parseInt(sessionNumber, 10);
    const type = (sessionType || '').trim();
    if (!n || n <= 0 || !type) return '';
    return `${toOrdinalSuffix(n)} ${type} of the ${titleBody}`;
}

function parseSessionNumberFromTitle(title) {
    const text = String(title || '').trim();
    const typeMatch = text.match(/(\d+)(?:st|nd|rd|th)\s+(?:Regular|Special|Emergency)\s+Session/i);
    if (typeMatch) {
        return parseInt(typeMatch[1], 10);
    }
    const startMatch = text.match(/^(\d+)(?:st|nd|rd|th)\b/i);
    return startMatch ? parseInt(startMatch[1], 10) : null;
}

async function fetchSessionNumberStats(excludeSessionId = null, sessionType = null) {
    let url = '../api/api_sessions.php?session_numbers=1';
    if (excludeSessionId) {
        url += `&exclude_id=${excludeSessionId}`;
    }
    if (sessionType) {
        url += `&session_type=${encodeURIComponent(sessionType)}`;
    }
    const response = await fetch(url);
    const data = await response.json();
    if (!data.success) {
        throw new Error(data.message || 'Failed to load session numbers');
    }
    return data;
}

function populateSessionNumberDropdown(selectEl, stats, selectedNumber = null, isCreate = true) {
    if (!selectEl || !stats) return;

    const used = new Set((stats.used_numbers || []).map(Number));
    const nextNumber = stats.next_number || 1;
    const defaultNumber = selectedNumber || nextNumber;

    selectEl.innerHTML = '';

    const sortedUsed = [...used].sort((a, b) => a - b);
    sortedUsed.forEach((n) => {
        const option = document.createElement('option');
        option.value = String(n);
        option.textContent = `${toOrdinalSuffix(n)} (in use)`;
        option.disabled = true;
        selectEl.appendChild(option);
    });

    const selectable = new Set([nextNumber]);
    if (!isCreate && defaultNumber && !used.has(defaultNumber)) {
        selectable.add(defaultNumber);
    }

    [...selectable].sort((a, b) => a - b).forEach((n) => {
        if (used.has(n)) return;

        const option = document.createElement('option');
        option.value = String(n);
        option.textContent = toOrdinalSuffix(n);
        if (n === defaultNumber) {
            option.selected = true;
        }
        selectEl.appendChild(option);
    });

    if (selectEl.options.length === 0) {
        const option = document.createElement('option');
        option.value = String(nextNumber);
        option.textContent = toOrdinalSuffix(nextNumber);
        option.selected = true;
        selectEl.appendChild(option);
    }
}

function updateSessionTitlePreview(numberSelect, typeSelect, titlePreview, titleBody = SESSION_TITLE_BODY) {
    const title = buildSessionTitle(numberSelect?.value, typeSelect?.value, titleBody);
    if (titlePreview) {
        titlePreview.value = title || 'Select session number and type to generate title';
    }
}

async function refreshSessionNumberDropdown({ numberSelectId, typeSelectId, excludeSessionId, selectedNumber = null, isCreate = true }) {
    const numberSelect = document.getElementById(numberSelectId);
    const typeSelect = document.getElementById(typeSelectId);
    if (!numberSelect) return null;

    const sessionType = typeSelect?.value?.trim() || '';
    if (!sessionType) {
        numberSelect.innerHTML = '<option value="">Select session type first</option>';
        return null;
    }

    const stats = await fetchSessionNumberStats(excludeSessionId, sessionType);
    const used = new Set((stats.used_numbers || []).map(Number));
    const nextNumber = stats.next_number || 1;

    let defaultNumber = selectedNumber;
    if (!defaultNumber || (isCreate && defaultNumber !== nextNumber) || (!isCreate && used.has(defaultNumber) && defaultNumber !== selectedNumber)) {
        defaultNumber = isCreate ? nextNumber : (selectedNumber && !used.has(selectedNumber) ? selectedNumber : nextNumber);
    }
    if (isCreate) {
        defaultNumber = nextNumber;
    }

    populateSessionNumberDropdown(numberSelect, stats, defaultNumber, isCreate);
    return stats;
}

function bindAutoSessionTitle(numberSelectId, typeSelectId, titlePreviewId, titleBody = SESSION_TITLE_BODY) {
    const numberSelect = document.getElementById(numberSelectId);
    const typeSelect = document.getElementById(typeSelectId);
    const titlePreview = document.getElementById(titlePreviewId);

    numberSelect?.addEventListener('change', () => {
        updateSessionTitlePreview(numberSelect, typeSelect, titlePreview, titleBody);
    });
}

async function initSessionTitleControls({ numberSelectId, typeSelectId, titlePreviewId, excludeSessionId = null, selectedNumber = null, isCreate = true }) {
    const numberSelect = document.getElementById(numberSelectId);
    const typeSelect = document.getElementById(typeSelectId);
    const titlePreview = document.getElementById(titlePreviewId);
    if (!numberSelect) return;

    let titleBody = SESSION_TITLE_BODY;

    const refreshNumbers = async (keepSelectedNumber = null) => {
        try {
            const stats = await refreshSessionNumberDropdown({
                numberSelectId,
                typeSelectId,
                excludeSessionId,
                selectedNumber: keepSelectedNumber,
                isCreate
            });
            if (stats) {
                titleBody = stats.title_body || SESSION_TITLE_BODY;
            }
            updateSessionTitlePreview(numberSelect, typeSelect, titlePreview, titleBody);
        } catch (error) {
            console.error('Error loading session numbers:', error);
            numberSelect.innerHTML = '<option value="">Failed to load session numbers</option>';
        }
    };

    typeSelect?.addEventListener('change', () => refreshNumbers());

    bindAutoSessionTitle(numberSelectId, typeSelectId, titlePreviewId, titleBody);
    await refreshNumbers(selectedNumber);
}

