// Toggle all staff checkboxes
window.toggleAllStaffCheckboxes = function (checkbox, containerId) {
    const container = document.getElementById(containerId + '-container');
    if (container) {
        const checkboxes = container.querySelectorAll('.create-session-staff-checkbox');
        checkboxes.forEach(cb => {
            cb.checked = checkbox.checked;
        });
    }
};


window.saveSession = async function (event) {
    event.preventDefault();
    const formData = new FormData(event.target);

    // Get base session data
    const venueId = formData.get('venue_id');
    const baseData = {
        session_number: parseInt(formData.get('session_number'), 10),
        session_type: formData.get('session_type'),
        session_date: formData.get('session_date'),
        start_time: formData.get('start_time'),
        end_time: formData.get('end_time'),
        status: 'Scheduled', // Always default to Scheduled
        venue_id: venueId ? parseInt(venueId) : null,
        presiding_officer: formData.get('presiding_officer') || null
    };

    if (!baseData.session_number || !baseData.session_type) {
        showNotification('Please select a session number and session type', 'error');
        return;
    }

    // Get assigned staff user IDs
    const assignedStaffIds = formData.getAll('assigned_staff[]').map(id => parseInt(id));
    baseData.user_ids = assignedStaffIds.length > 0 ? assignedStaffIds : [];

    const sessionDate = formData.get('session_date');

    // Handle recurring sessions
    const repeatDays = formData.getAll('repeat_days[]').map(d => parseInt(d));
    const repeatWeeks = parseInt(formData.get('repeat_weeks')) || 1;

    // If no days selected, create single session
    if (repeatDays.length === 0) {
        await createSingleSession(baseData);
    } else {
        // Create multiple sessions for selected days
        await createRecurringSessions(baseData, repeatDays, repeatWeeks);
    }
};

async function createSingleSession(sessionData) {
    try {
        // Extract user_ids before sending (they're not part of session creation)
        const userIds = sessionData.user_ids || [];
        delete sessionData.user_ids;

        const response = await fetch('../api/api_sessions.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(sessionData)
        });
        const result = await response.json();
        if (result.success) {
            const sessionId = result.session_id || result.id;

            // Assign staff if user_ids were provided
            if (userIds.length > 0) {
                try {
                    await fetch('../api/api_sessions.php', {
                        method: 'PUT',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            session_id: sessionId,
                            action: 'update_assignments',
                            user_ids: userIds
                        })
                    });
                } catch (assignError) {
                    console.error('Error assigning staff:', assignError);
                    // Don't fail the whole operation if assignment fails
                }
            }

            showNotification('Session created successfully', 'success');
            document.getElementById('createSessionModal').remove();

            // Ensure newly created session appears immediately
            if (window.cachedSessions) {
                window.cachedSessions = null;
            }
            if (window.activeSection !== 'sessions') {
            showSection('sessions');
            } else if (window.renderSessionsEnhanced) {
                window.renderSessionsEnhanced();
            } else if (typeof renderSessions === 'function') {
                renderSessions();
            }
        } else {
            showNotification(result.message || 'Failed to create session', 'error');
        }
    } catch (e) {
        console.error('Save error:', e);
        showNotification('Error creating session', 'error');
    }
}

/**
 * Reschedule a locked (Missed / Postponed) session
 * Allows changing date, start/end time, and venue only, and resets status to Scheduled.
 */
window.rescheduleSession = async function (sessionId) {
    try {
        // Prefer cached data
        let session = null;
        if (window.cachedSessions && window.cachedSessions.length > 0) {
            session = window.cachedSessions.find(s => (s.session_id || s.id) == sessionId);
        }

        if (!session) {
            const resp = await fetch(`../api/api_sessions.php?id=${sessionId}`);
            const data = await resp.json();
            if (data.success && data.session) {
                session = data.session;
            }
        }

        if (!session) {
            showNotification('Session not found', 'error');
            return;
        }

        // Fetch venues from API
        let venues = [];
        try {
            const venuesResp = await fetch('../api/api_venues.php');
            const venuesData = await venuesResp.json();
            if (venuesData.success && venuesData.venues) {
                venues = venuesData.venues;
            }
        } catch (e) {
            console.error('Error fetching venues:', e);
        }

        const existing = document.getElementById('rescheduleSessionModal');
        if (existing) existing.remove();

        // Build venue options
        let venueOptions = '<option value="">Select a venue...</option>';
        venues.forEach(venue => {
            const selected = (session.venue_id == venue.id || session.venue === venue.venue_name) ? 'selected' : '';
            venueOptions += `<option value="${venue.id}" data-address="${venue.address || ''}" ${selected}>${venue.venue_name}</option>`;
        });

        const today = new Date().toISOString().split('T')[0];

        const modalHtml = `
        <div id="rescheduleSessionModal" class="fixed inset-0 bg-black bg-opacity-50 overflow-y-auto h-full w-full flex items-center justify-center z-50 backdrop-blur-sm">
            <div class="relative p-6 border w-full max-w-lg shadow-2xl rounded-2xl bg-white animate-fade-in-up m-4 max-h-[90vh] overflow-y-auto">
                <div class="flex justify-between items-center mb-6">
                    <div>
                        <h3 class="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            <i class="bi bi-arrow-repeat text-blue-600"></i>
                            Reschedule Session
                        </h3>
                        <p class="text-sm text-gray-500 mt-1">Update only the schedule and venue for this session.</p>
                    </div>
                    <button onclick="document.getElementById('rescheduleSessionModal').remove()" class="text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg p-2 transition">
                        <i class="bi bi-x-lg text-xl"></i>
                    </button>
                </div>
                <form onsubmit="window.saveRescheduledSession(event, ${sessionId})" class="space-y-5">
                    <div>
                        <label class="block text-sm font-semibold text-gray-700 mb-2">Session Title</label>
                        <p class="text-sm font-medium text-gray-900">${session.title}</p>
                    </div>
                    <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Session Date *</label>
                            <input type="date" name="session_date" required min="${today}" value="${session.session_date}" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition">
                        </div>
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Start Time *</label>
                            <input type="time" name="start_time" required value="${session.start_time || ''}" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition">
                        </div>
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">End Time *</label>
                            <input type="time" name="end_time" required value="${session.end_time || ''}" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition">
                        </div>
                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-2">Venue</label>
                            <div class="relative">
                                <select name="venue_id" id="reschedule-venue-select" class="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition">
                                    ${venueOptions}
                                </select>
                                <div id="venue-address-tooltip" class="hidden absolute left-0 right-0 top-full mt-1 p-2 bg-gray-800 text-white text-xs rounded shadow-lg z-10 pointer-events-none">
                                    <div class="font-semibold mb-1">Address:</div>
                                    <div id="venue-address-text"></div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="flex gap-3 pt-4 border-t border-gray-200">
                        <button type="button" onclick="document.getElementById('rescheduleSessionModal').remove()" class="flex-1 px-4 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 font-medium transition">
                            Cancel
                        </button>
                        <button type="submit" class="flex-1 px-4 py-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-lg hover:from-blue-700 hover:to-blue-800 font-medium shadow-lg shadow-blue-500/30 transition-all">
                            <i class="bi bi-check-lg mr-2"></i>Reschedule
                        </button>
                    </div>
                </form>
            </div>
        </div>`;

        document.body.insertAdjacentHTML('beforeend', modalHtml);

        // Add hover functionality to show address
        const venueSelect = document.getElementById('reschedule-venue-select');
        const tooltip = document.getElementById('venue-address-tooltip');
        const addressText = document.getElementById('venue-address-text');
        
        const updateTooltip = function() {
            if (!venueSelect || !tooltip || !addressText) return;
            const selectedOption = venueSelect.options[venueSelect.selectedIndex];
            const address = selectedOption ? selectedOption.getAttribute('data-address') : '';
            if (address && address.trim()) {
                addressText.textContent = address;
            } else {
                addressText.textContent = 'No address available';
            }
        };

        if (venueSelect && tooltip && addressText) {
            // Show tooltip on hover
            venueSelect.addEventListener('mouseenter', function() {
                updateTooltip();
                tooltip.classList.remove('hidden');
            });

            venueSelect.addEventListener('mouseleave', function() {
                tooltip.classList.add('hidden');
            });

            // Update tooltip when selection changes
            venueSelect.addEventListener('change', function() {
                updateTooltip();
                // Show briefly after change
                tooltip.classList.remove('hidden');
                setTimeout(() => {
                    if (document.activeElement !== venueSelect) {
                        tooltip.classList.add('hidden');
                    }
                }, 2000);
            });

            // Initial tooltip update
            updateTooltip();
        }
    } catch (e) {
        console.error('Error opening reschedule modal:', e);
        showNotification('Error opening reschedule modal', 'error');
    }
};

window.saveRescheduledSession = async function (event, sessionId) {
    event.preventDefault();
    const formData = new FormData(event.target);

    const venueId = formData.get('venue_id');
    const payload = {
        session_id: sessionId,
        session_date: formData.get('session_date'),
        start_time: formData.get('start_time'),
        end_time: formData.get('end_time'),
        venue_id: venueId ? parseInt(venueId) : null,
        status: 'Scheduled'
    };

    try {
        const response = await fetch('../api/api_sessions.php', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Session rescheduled successfully', 'success');
            document.getElementById('rescheduleSessionModal')?.remove();

            // Clear cache so updated data is fetched
            if (window.cachedSessions) {
                window.cachedSessions = window.cachedSessions.filter(s => (s.session_id || s.id) != sessionId);
            }

            if (window.renderSessionsEnhanced) {
                window.renderSessionsEnhanced();
            } else if (typeof renderSessions === 'function') {
                renderSessions();
            }

            // If viewing details, refresh them
            if (typeof viewSessionDetails === 'function' && document.getElementById('session-agenda-list')) {
                viewSessionDetails(sessionId);
            }
        } else {
            showNotification(result.message || 'Failed to reschedule session', 'error');
        }
    } catch (e) {
        console.error('Error saving rescheduled session:', e);
        showNotification('Error rescheduling session', 'error');
    }
};

async function createRecurringSessions(baseData, repeatDays, repeatWeeks) {
    // Extract user_ids before processing (they'll be assigned to all sessions)
    const userIds = baseData.user_ids || [];
    delete baseData.user_ids;

    const baseDate = new Date(baseData.session_date);
    const sessionsToCreate = [];
    const baseDayOfWeek = baseDate.getDay(); // 0 = Sunday, 1 = Monday, etc.
    let nextSessionNumber = baseData.session_number;

    // Generate dates for each selected day over the specified weeks
    for (let week = 0; week < repeatWeeks; week++) {
        repeatDays.forEach(dayOfWeek => {
            const sessionDate = new Date(baseDate);
            // Calculate days to add: find next occurrence of this day of week
            let daysToAdd = dayOfWeek - baseDayOfWeek;
            if (daysToAdd < 0) daysToAdd += 7; // If day has passed this week, go to next week
            daysToAdd += (week * 7); // Add weeks

            sessionDate.setDate(baseDate.getDate() + daysToAdd);

            // Only create if date is not in the past (for week 0, only future dates)
            if (week === 0 && daysToAdd < 0) {
                daysToAdd += 7; // Move to next week if day has passed
                sessionDate.setDate(baseDate.getDate() + daysToAdd);
            }

            const sessionData = {
                ...baseData,
                session_number: nextSessionNumber,
                session_date: sessionDate.toISOString().split('T')[0]
            };
            sessionsToCreate.push(sessionData);
            nextSessionNumber++;
        });
    }

    // Remove duplicates (in case same date appears multiple times)
    const uniqueSessions = [];
    const seenDates = new Set();
    sessionsToCreate.forEach(session => {
        if (!seenDates.has(session.session_date)) {
            seenDates.add(session.session_date);
            uniqueSessions.push(session);
        }
    });

    // Create all sessions
    let successCount = 0;
    let failCount = 0;
    const createdSessions = [];

    for (const sessionData of uniqueSessions) {
        try {
            const response = await fetch('../api/api_sessions.php', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(sessionData)
            });
            const result = await response.json();
            if (result.success) {
                successCount++;
                // Store created session for reminder generation
                const sessionId = result.session_id || result.id || result.session?.session_id;
                createdSessions.push({
                    session_id: sessionId,
                    ...sessionData
                });

                // Assign staff if user_ids were provided
                if (userIds.length > 0 && sessionId) {
                    try {
                        await fetch('../api/api_sessions.php', {
                            method: 'PUT',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                session_id: sessionId,
                                action: 'update_assignments',
                                user_ids: userIds
                            })
                        });
                    } catch (assignError) {
                        console.error('Error assigning staff to session:', sessionId, assignError);
                        // Don't fail the whole operation if assignment fails
                    }
                }
            } else {
                failCount++;
            }
        } catch (e) {
            failCount++;
        }
    }

    // Close modal and refresh sessions list
    const modal = document.getElementById('createSessionModal');
    if (modal) modal.remove();

    if (failCount === 0) {
        showNotification(`Successfully created ${successCount} session(s)`, 'success');
    } else {
        showNotification(`Created ${successCount} session(s), ${failCount} failed`, 'warning');
    }

    if (window.cachedSessions) {
        window.cachedSessions = null;
    }
    if (window.activeSection !== 'sessions') {
    showSection('sessions');
    } else if (window.renderSessionsEnhanced) {
        window.renderSessionsEnhanced();
    } else if (typeof renderSessions === 'function') {
        renderSessions();
    }
}

/**
 * Auto-generate reminder for a session
 * Creates reminders for all Administrator and Staff users
 */
async function autoGenerateSessionReminder(session) {
    try {
        // Validate required fields
        if (!session || !session.session_date || !session.title || !session.session_type) {
            console.warn('Cannot generate reminder: missing required session data', session);
            return;
        }

        // Ensure we have session_id
        if (!session.session_id) {
            console.warn('Cannot generate reminder: missing session_id', session);
            return;
        }

        // Format date and time
        const sessionDate = new Date(session.session_date);
        if (isNaN(sessionDate.getTime())) {
            console.warn('Invalid session date:', session.session_date);
            return;
        }

        const dateStr = sessionDate.toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });

        let timeStr = 'TBD';
        if (session.actual_start) {
            const startTime = new Date(session.actual_start);
            if (!isNaN(startTime.getTime())) {
                timeStr = startTime.toLocaleTimeString('en-US', {
                    hour: '2-digit',
                    minute: '2-digit',
                    hour12: true
                });
            }
        }

        // Format venue
        const venue = session.venue || 'TBD';

        // Construct a highly accurate message
        const sessionDateStr = sessionDate.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const sessionTimeText = timeStr === 'TBD' ? 'Time TBD' : timeStr;
        const label = '1-hour mark'; // Assuming this is for the 1-hour reminder
        const reminderMessage = `Scheduled Session: "${session.title}"\n\nSession Time: ${sessionDateStr} at ${sessionTimeText}\nMilestone: ${label}\n\nNote: You will receive a system alert when we reach the ${label} mark before this session starts.`;

        // Calculate reminder date (1 hour before session, or use session date if no time)
        let reminderDate = new Date(sessionDate);
        if (session.actual_start) {
            const startTime = new Date(session.actual_start);
            if (!isNaN(startTime.getTime())) {
                reminderDate = new Date(startTime);
                reminderDate.setHours(reminderDate.getHours() - 1);
            }
        } else {
            reminderDate.setHours(9, 0, 0, 0); // Default to 9 AM if no time
            reminderDate.setDate(reminderDate.getDate() - 1); // 1 day before if no specific time
        }

        // Call API to create role-based reminders
        const response = await fetch('../api/api_reminders.php', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                title: 'Upcoming Session Reminder',
                message: reminderMessage,
                reminder_date: reminderDate.toISOString(),
                related_type: 'Session',
                related_id: session.session_id || session.id,
                target_roles: 'Super Admin,Admin,Staff',
                role_based: true
            })
        });

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();
        if (data.success) {
            console.log(`✅ Auto-generated ${data.count || 'reminders'} for session ${session.session_id}`);
        } else {
            console.error('❌ Reminder API returned error:', data.message);
        }
    } catch (error) {
        console.error('❌ Error auto-generating reminder:', error);
        // Don't show error to user, as this is a background operation
    }
}

window.showDeleteSessionModal = function (sessionId) {
    return new Promise((resolve) => {
        const existing = document.getElementById('deleteSessionModal');
        if (existing) existing.remove();

        const modalHtml = `
        <div id="deleteSessionModal" class="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center animate-fade-in p-4">
            <div class="bg-white dark:bg-dark-card rounded-2xl shadow-2xl max-w-md w-full overflow-hidden animate-fade-in-up border border-gray-100 dark:border-dark-border">
                <div class="p-8">
                    <div class="flex items-center gap-5 mb-6">
                        <div class="w-14 h-14 rounded-2xl bg-red-50 dark:bg-red-900/20 flex items-center justify-center flex-shrink-0 shadow-inner">
                            <i class="bi bi-exclamation-triangle-fill text-red-600 dark:text-red-400 text-2xl"></i>
                        </div>
                        <div>
                            <h3 class="text-xl font-black text-gray-900 dark:text-white">Delete Session?</h3>
                            <p class="text-sm text-gray-500 dark:text-dark-muted font-medium">Are you sure you want to delete this session?</p>
                        </div>
                    </div>
                    <p class="text-gray-600 dark:text-dark-text text-sm leading-relaxed mb-4 pl-[76px] font-medium">This action will move the session to Inactive status. You can restore it later if needed.</p>
                    <label class="flex items-center gap-3 pl-[76px] mb-6 cursor-pointer group">
                        <input type="checkbox" id="permanentDeleteCheckbox" class="w-5 h-5 text-red-600 border-gray-300 dark:border-dark-border rounded focus:ring-red-500">
                        <span class="text-sm font-medium text-gray-700 dark:text-dark-text group-hover:text-red-600 dark:group-hover:text-red-400 transition-colors">Hard delete</span>
                    </label>
                    <div class="flex justify-end gap-3">
                        <button id="deleteSessionCancelBtn" class="px-6 py-3 bg-gray-50 dark:bg-dark-bg text-gray-700 dark:text-dark-text border border-gray-200 dark:border-dark-border rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 font-bold transition-all text-sm">Cancel</button>
                        <button id="deleteSessionConfirmBtn" class="px-6 py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 font-bold transition-all shadow-lg shadow-red-500/30 text-sm active:scale-95">Delete Session</button>
                    </div>
                </div>
            </div>
        </div>`;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        document.body.style.overflow = 'hidden';

        document.getElementById('deleteSessionConfirmBtn').onclick = function () {
            const modal = document.getElementById('deleteSessionModal');
            const permanent = document.getElementById('permanentDeleteCheckbox')?.checked || false;
            if (modal) modal.remove();
            document.body.style.overflow = '';
            resolve({ confirmed: true, permanentDelete: permanent });
        };

        document.getElementById('deleteSessionCancelBtn').onclick = function () {
            const modal = document.getElementById('deleteSessionModal');
            if (modal) modal.remove();
            document.body.style.overflow = '';
            resolve({ confirmed: false });
        };

        document.getElementById('deleteSessionModal').onclick = function (e) {
            if (e.target === this) {
                this.remove();
                document.body.style.overflow = '';
                resolve({ confirmed: false });
            }
        };
    });
};

window.deleteSession = async function (sessionId) {
    const { confirmed, permanentDelete } = await window.showDeleteSessionModal(sessionId);

    if (!confirmed) return;

    const passwordOk = await window.promptPasswordConfirmation({
        title: 'Confirm Delete Session',
        message: permanentDelete
            ? 'Enter your password to permanently delete this session and all related data.'
            : 'Enter your password to move this session to Inactive status.',
        confirmText: 'Confirm Delete'
    });
    if (!passwordOk) return;

    try {
        const response = await fetch('../api/api_sessions.php', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ session_id: sessionId, permanent: permanentDelete })
        });
        const result = await response.json();
        if (result.success) {
            showNotification(result.message || (permanentDelete ? 'Session permanently deleted.' : 'Session has been moved to Inactive status.'), 'success');
            if (window.renderSessionsEnhanced) {
                window.renderSessionsEnhanced();
            } else if (typeof renderSessions === 'function') {
                renderSessions();
            }
            if (document.getElementById('session-agenda-list')) {
                showSection('sessions');
            }
        } else {
            showNotification('Failed to delete session: ' + (result.message || 'Unknown error'), 'error');
        }
    } catch (e) {
        console.error('Delete error:', e);
        showNotification('Error deleting session', 'error');
    }
};


