window.showNotification = function (message, type = 'info') {
    // Remove any existing notifications
    const existing = document.querySelectorAll('.custom-notification');
    existing.forEach(n => n.remove());

    const icons = {
        success: 'bi-check-circle-fill',
        error: 'bi-x-circle-fill',
        warning: 'bi-exclamation-triangle-fill',
        info: 'bi-info-circle-fill'
    };

    const colors = {
        success: {
            bg: 'bg-green-50 dark:bg-green-950/40',
            border: 'border-green-200 dark:border-green-900/50',
            text: 'text-green-800 dark:text-green-300',
            icon: 'text-green-600 dark:text-green-400',
            progress: 'bg-green-600 dark:bg-green-500'
        },
        error: {
            bg: 'bg-red-50 dark:bg-red-950/40',
            border: 'border-red-200 dark:border-red-900/50',
            text: 'text-red-800 dark:text-red-300',
            icon: 'text-red-600 dark:text-red-400',
            progress: 'bg-red-600 dark:bg-red-500'
        },
        warning: {
            bg: 'bg-orange-50 dark:bg-orange-950/40',
            border: 'border-orange-200 dark:border-orange-900/50',
            text: 'text-orange-800 dark:text-orange-300',
            icon: 'text-orange-600 dark:text-orange-400',
            progress: 'bg-orange-600 dark:bg-orange-500'
        },
        info: {
            bg: 'bg-blue-50 dark:bg-blue-950/40',
            border: 'border-blue-200 dark:border-blue-900/50',
            text: 'text-blue-800 dark:text-blue-300',
            icon: 'text-blue-600 dark:text-blue-400',
            progress: 'bg-blue-600 dark:bg-blue-500'
        }
    };

    const color = colors[type] || colors.info;
    const icon = icons[type] || icons.info;

    const notificationHtml = `
        <div class="custom-notification fixed top-4 right-4 z-[9999] animate-fade-in-up" style="animation: slideInRight 0.3s ease-out">
            <div class="${color.bg} ${color.border} border-l-4 rounded-lg shadow-2xl p-4 pr-12 min-w-[320px] max-w-md backdrop-blur-sm bg-opacity-95 dark:bg-opacity-80">
                <div class="flex items-start gap-3">
                    <i class="bi ${icon} ${color.icon} text-xl flex-shrink-0 mt-0.5"></i>
                    <div class="flex-1">
                        <p class="${color.text} font-medium text-sm leading-relaxed">${message}</p>
                    </div>
                    <button onclick="this.closest('.custom-notification').remove()" class="${color.text} hover:opacity-70 transition absolute top-3 right-3">
                        <i class="bi bi-x-lg text-sm"></i>
                    </button>
                </div>
                <div class="mt-3 h-1 bg-gray-200 dark:bg-slate-700 bg-opacity-30 rounded-full overflow-hidden">
                    <div class="${color.progress} h-full rounded-full notification-progress" style="animation: shrink 3s linear forwards"></div>
                </div>
            </div>
        </div>
    `;

    document.body.insertAdjacentHTML('beforeend', notificationHtml);

    // Auto remove after 3 seconds
    setTimeout(() => {
        const notifications = document.querySelectorAll('.custom-notification');
        notifications.forEach(notification => {
            notification.style.animation = 'slideOutRight 0.3s ease-in';
            setTimeout(() => notification.remove(), 300);
        });
    }, 3000);
};

