window.deleteAgenda = async function (agendaId) {
    const confirmed = await confirm('Delete this agenda item?');
    if (!confirmed) return;

    const passwordOk = await window.promptPasswordConfirmation({
        title: 'Confirm Delete Agenda',
        message: 'Enter your password to delete this agenda.',
        confirmText: 'Confirm Delete'
    });
    if (!passwordOk) return;

    try {
        const response = await fetch('../api/api_agendas.php', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ agenda_id: agendaId })
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Agenda deleted successfully', 'success');
            renderAgendas();
        } else {
            showNotification('Failed to delete agenda', 'error');
        }
    } catch (e) {
        console.error('Delete error:', e);
        showNotification('Error deleting agenda', 'error');
    }
};

