window.renderCalendarGrid = function () {
    const gridContainer = document.getElementById('calendarGrid');
    if (!gridContainer) return;

    const calendarMeta = getCurrentCalendarMeta();

    if (calendarView === 'month') {
        // Month view grid
        const daysInMonth = new Date(calendarMeta.year, calendarMeta.month, 0).getDate();
        const firstDay = new Date(calendarMeta.year, calendarMeta.month - 1, 1).getDay();

        let gridHTML = '<div class="grid grid-cols-7">';

        // Day headers
        const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        dayNames.forEach(day => {
            gridHTML += `<div class="p-3 text-center font-semibold text-gray-600 bg-gray-50 border-b border-r border-gray-200">${day}</div>`;
        });

        // Empty cells before first day
        for (let i = 0; i < firstDay; i++) {
            gridHTML += '<div class="p-3 bg-gray-50 border-b border-r border-gray-200 min-h-[80px]"></div>';
        }

        // Days of month
        for (let day = 1; day <= daysInMonth; day++) {
            const isToday = day === calendarMeta.todayDate &&
                calendarMeta.month === new Date().getMonth() + 1 &&
                calendarMeta.year === new Date().getFullYear();

            gridHTML += `
                <div class="p-3 border-b border-r border-gray-200 min-h-[80px] hover:bg-gray-50 transition ${isToday ? 'bg-red-50' : 'bg-white'}">
                    <div class="font-semibold ${isToday ? 'text-red-600' : 'text-gray-900'}">${day}</div>
                </div>
            `;
        }

        gridHTML += '</div>';
        gridContainer.innerHTML = gridHTML;
    } else if (calendarView === 'week') {
        gridContainer.innerHTML = '<div class="p-8 text-center text-gray-500">Week view coming soon</div>';
    } else {
        gridContainer.innerHTML = '<div class="p-8 text-center text-gray-500">Day view coming soon</div>';
    }
};

