window.renderCalendarGrid = function () {
    const gridContainer = document.getElementById('calendarGrid');
    if (!gridContainer) return;

    const calendarMeta = getCurrentCalendarMeta();
    const daysInMonth = new Date(calendarMeta.year, calendarMeta.month, 0).getDate();
    const firstDay = new Date(calendarMeta.year, calendarMeta.month - 1, 1).getDay();
    const today = new Date();
    const isCurrentMonth = calendarMeta.month === today.getMonth() + 1 && calendarMeta.year === today.getFullYear();

    let gridHTML = '<div class="grid grid-cols-7 gap-2">';

    // Day headers
    const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    dayNames.forEach(day => {
        gridHTML += `<div class="p-3 text-center font-bold text-gray-700 text-sm">${day}</div>`;
    });

    // Empty cells before first day
    for (let i = 0; i < firstDay; i++) {
        gridHTML += '<div class="aspect-square"></div>';
    }

    // Days of month
    for (let day = 1; day <= daysInMonth; day++) {
        const dateKey = `${calendarMeta.year}-${String(calendarMeta.month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        const isToday = isCurrentMonth && day === today.getDate();

        // Check for sessions on this date
        const sessionsOnDate = window.calendarSessions.filter(s => s.session_date === dateKey);
        const hasNote = window.calendarNotes && window.calendarNotes[dateKey];

        gridHTML += `
            <div onclick="openDateModal('${dateKey}', ${day})" 
                 class="aspect-square border-2 ${isToday ? 'border-red-500 bg-red-50' : 'border-gray-200'} rounded-lg p-2 hover:border-red-400 hover:shadow-md transition-all cursor-pointer group">
                <div class="h-full flex flex-col">
                    <div class="flex items-center justify-between mb-1">
                        <span class="font-bold ${isToday ? 'text-red-600' : 'text-gray-900'} group-hover:text-red-600">${day}</span>
                        ${hasNote ? '<i class="bi bi-sticky-fill text-blue-500 text-xs"></i>' : ''}
                    </div>
                    <div class="flex-1 overflow-hidden">
                        ${sessionsOnDate.map(s => `
                            <div class="text-xs px-1 py-0.5 bg-red-100 text-red-700 rounded mb-1 truncate" title="${s.title}">
                                ${s.title}
                            </div>
                        `).join('')}
                    </div>
                </div>
            </div>
        `;
    }

    gridHTML += '</div>';
    gridContainer.innerHTML = gridHTML;
};

