window.navigateCalendar = function (direction) {
    const base = calendarCurrentDate instanceof Date ? new Date(calendarCurrentDate) : new Date();
    if (direction === 'prev') {
        if (calendarView === 'week') {
            base.setDate(base.getDate() - 7);
        } else if (calendarView === 'day') {
            base.setDate(base.getDate() - 1);
        } else {
            base.setMonth(base.getMonth() - 1);
        }
    } else if (direction === 'next') {
        if (calendarView === 'week') {
            base.setDate(base.getDate() + 7);
        } else if (calendarView === 'day') {
            base.setDate(base.getDate() + 1);
        } else {
            base.setMonth(base.getMonth() + 1);
        }
    } else if (direction === 'today') {
        base.setTime(new Date().getTime());
    }

    // Constraint: Limit to Electoral Term (June 30, 2025 to June 30, 2028)
    const termStart = new Date(2025, 5, 30); // June 30, 2025 (Month is 0-indexed: 5 = June)
    const termEnd = new Date(2028, 5, 30);   // June 30, 2028
    
    if (base < termStart) {
        base.setTime(termStart.getTime());
    } else if (base > termEnd) {
        base.setTime(termEnd.getTime());
    }

    calendarCurrentDate = base;
    window.currentCalendarMonth = base.getMonth() + 1;
    window.currentCalendarYear = base.getFullYear();
    renderCalendarEnhanced();
};

