window.filterDeadlinesByStatus = function (status) {
    const items = document.querySelectorAll('.deadline-item');
    items.forEach(item => {
        if (!status || item.dataset.status === status) {
            item.style.display = '';
        } else {
            item.style.display = 'none';
        }
    });
};

window.filterDeadlinesByPriority = function (priority) {
    const items = document.querySelectorAll('.deadline-item');
    items.forEach(item => {
        if (!priority || item.dataset.priority === priority) {
            item.style.display = '';
        } else {
            item.style.display = 'none';
        }
    });
};

window.searchDeadlines = function (query) {
    const items = document.querySelectorAll('.deadline-item');
    const lowerQuery = query.toLowerCase();

    items.forEach(item => {
        const text = item.textContent.toLowerCase();
        if (text.includes(lowerQuery)) {
            item.style.display = '';
        } else {
            item.style.display = 'none';
        }
    });
};

window.editDeadline = function (deadlineId) {
    showNotification('Edit deadline functionality coming soon', 'info');
};

window.deleteDeadline = async function (deadlineId) {
    const confirmed = await confirm('Delete this deadline?');
    if (!confirmed) return;

    const passwordOk = await window.promptPasswordConfirmation({
        title: 'Confirm Delete Deadline',
        message: 'Enter your password to delete this deadline.',
        confirmText: 'Confirm Delete'
    });
    if (!passwordOk) return;

    try {
        const response = await fetch('../api/api_deadlines.php', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ deadline_id: deadlineId })
        });
        const result = await response.json();
        if (result.success) {
            showNotification('Deadline deleted successfully', 'success');
            renderDeadlines();
        } else {
            showNotification('Failed to delete deadline', 'error');
        }
    } catch (e) {
        console.error('Delete error:', e);
        showNotification('Error deleting deadline', 'error');
    }
};

