window.renderAuditLogsEnhancedPremium = async function () {
    try {
        const response = await fetch('../api/api_logs.php');
        const data = await response.json();

        if (!data.success) {
            showNotification('Failed to load audit logs', 'error');
            return;
        }

        const logs = data.logs || [];
        const criticalCount = logs.filter(l => l.severity === 'Critical' || (l.action && (l.action.toLowerCase().includes('delete') || l.action.toLowerCase().includes('fail')))).length;

        const html = `
    < div class="space-y-6 animate-fade-in-up pb-10" >
            <div class="relative overflow-hidden rounded-2xl bg-gradient-to-br from-red-600 via-red-700 to-red-800 p-8 shadow-xl mb-6">
                <div class="absolute inset-0 bg-black opacity-10"></div>
                <div class="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-32 -mt-32"></div>
                <div class="relative z-10 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div>
                        <h1 class="text-3xl font-bold mb-2">System Audit Logs</h1>
                        <p class="text-red-100 text-sm opacity-90 tracking-wide">Monitor administrative activities and security events</p>
                    </div>
                    <button onclick="renderAuditLogs()" class="px-5 py-2 bg-white/10 hover:bg-white/20 border border-white/20 rounded-xl text-sm font-bold transition-all">
                        <i class="bi bi-arrow-clockwise mr-2"></i> Refresh Data
                    </button>
                </div>
            </div>

            <div class="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div class="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div class="flex items-center gap-4">
                        <div class="w-14 h-14 bg-red-100 rounded-2xl flex items-center justify-center text-red-600">
                            <i class="bi bi-shield-check text-2xl"></i>
                        </div>
                        <div>
                            <p class="text-xs text-gray-500 uppercase font-black tracking-widest">Logged Activities</p>
                            <h3 class="text-3xl font-black text-gray-900">${logs.length}</h3>
                        </div>
                    </div>
                </div>
                <div class="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div class="flex items-center gap-4">
                        <div class="w-14 h-14 bg-amber-100 rounded-2xl flex items-center justify-center text-amber-600">
                            <i class="bi bi-exclamation-octagon text-2xl"></i>
                        </div>
                        <div>
                            <p class="text-xs text-gray-500 uppercase font-black tracking-widest">Critical Events</p>
                            <h3 class="text-3xl font-black text-gray-900">${criticalCount}</h3>
                        </div>
                    </div>
                </div>
            </div>

            <div class="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-wrap gap-4">
                <div class="relative flex-1">
                    <i class="bi bi-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                    <input type="text" id="logSearch" onkeyup="filterAuditLogs()" placeholder="Search activities..." 
                        class="w-full pl-11 pr-4 py-3 bg-gray-50 border-0 rounded-xl focus:ring-2 focus:ring-red-500 outline-none transition-all text-sm">
                </div>
            </div>

            <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <table class="w-full text-left" id="auditLogsTable">
                    <thead class="bg-gray-50 text-[10px] uppercase text-gray-500 font-black tracking-widest">
                        <tr>
                            <th class="p-4 pl-6">Actor</th>
                            <th class="p-4">Action Event</th>
                            <th class="p-4">Timestamp</th>
                            <th class="p-4 pr-6 text-right">Severity</th>
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-gray-100 text-sm">
                        ${logs.length > 0 ? logs.map(l => {
            const date = new Date(l.created_at);
            const isCritical = (l.action && (l.action.toLowerCase().includes('delete') || l.action.toLowerCase().includes('fail')));
            return `
                            <tr class="hover:bg-gray-50/50 transition-all log-row group" data-search="${l.user_name} ${l.action} ${l.description}">
                                <td class="p-4 pl-6">
                                    <div class="flex items-center gap-3">
                                        <div class="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center text-gray-600 font-bold group-hover:bg-red-100 group-hover:text-red-600 transition-colors">
                                            ${(l.user_name || 'S').charAt(0)}
                                        </div>
                                        <span class="font-bold text-gray-900">${l.user_name || 'System'}</span>
                                    </div>
                                </td>
                                <td class="p-4">
                                    <div class="font-medium text-gray-700">${l.action}</div>
                                    <div class="text-xs text-gray-500 max-w-xs truncate" title="${l.description}">${l.description || '-'}</div>
                                </td>
                                <td class="p-4 text-gray-500 text-xs">
                                    ${date.toLocaleDateString()} ${date.toLocaleTimeString()}
                                </td>
                                <td class="p-4 pr-6 text-right">
                                    <span class="px-2 py-1 rounded-md text-[10px] font-black uppercase ${isCritical ? 'bg-red-100 text-red-600' : 'bg-gray-100 text-gray-600'}">
                                        ${isCritical ? 'CRITICAL' : 'INFO'}
                                    </span>
                                </td>
                            </tr>
                            `;
        }).join('') : `
                        <tr><td colspan="4" class="p-16 text-center text-gray-400 italic">No system logs recorded</td></tr>
                        `}
                    </tbody>
                </table>
            </div>
        </div >
    `;
        document.getElementById('content-area').innerHTML = html;
    } catch (e) {
        showNotification('Error loading audit logs', 'error');
    }
};

function filterAuditLogs() {
    const search = document.getElementById('logSearch').value.toLowerCase();
    const rows = document.querySelectorAll('.log-row');
    rows.forEach(row => {
        const text = row.getAttribute('data-search').toLowerCase();
        row.style.display = text.includes(search) ? '' : 'none';
    });
}

