window.saveDeadlineFiltered = async function (e) {
    e.preventDefault();
    const fd = new FormData(e.target);
    const data = Object.fromEntries(fd.entries());

    // API call
    try {
        const res = await fetch('../api/api_deadlines.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        const json = await res.json();
        if (json.success) {
            showNotification('Deadline set successfully', 'success');
            document.getElementById('createDeadlineModal').remove();
            renderDeadlines();
        } else {
            showNotification(json.message || 'Error setting deadline', 'error');
        }
    } catch (err) {
        console.error(err);
        showNotification('Error saving deadline', 'error');
    }
};

