// ============================================
// GLOBAL SEARCH ENGINE LOGIC
// ============================================

document.addEventListener('DOMContentLoaded', function () {
    const searchInput = document.getElementById('global-search-input');
    const searchOverlay = document.getElementById('global-search-overlay');
    const searchResults = document.getElementById('global-search-results');
    const closeBtn = document.getElementById('global-search-close');
    let searchTimeout;

    if (searchInput) {
        searchInput.addEventListener('input', function (e) {
            const query = e.target.value.trim();

            clearTimeout(searchTimeout);
            if (query.length < 2) {
                searchResults.innerHTML = '';
                searchResults.classList.add('hidden');
                return;
            }

            searchTimeout = setTimeout(() => {
                performGlobalSearch(query);
            }, 300);
        });

        // Close on Esc
        searchInput.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                closeGlobalSearch();
            }
        });
    }

    if (closeBtn) {
        closeBtn.onclick = closeGlobalSearch;
    }

    window.closeGlobalSearch = function () {
        if (searchOverlay) {
            searchOverlay.classList.remove('opacity-100', 'translate-y-0');
            searchOverlay.classList.add('opacity-0', '-translate-y-full', 'pointer-events-none');
            if (searchInput) {
                searchInput.value = '';
                searchInput.blur();
            }
            if (searchResults) {
                searchResults.innerHTML = '';
                searchResults.classList.add('hidden');
            }
        }
    };

    window.openGlobalSearch = function () {
        if (searchOverlay) {
            searchOverlay.classList.add('opacity-100', 'translate-y-0');
            searchOverlay.classList.remove('opacity-0', '-translate-y-full', 'pointer-events-none');
            if (searchInput) {
                searchInput.focus();
            }
        }
    };
});

async function performGlobalSearch(query) {
    const searchResults = document.getElementById('global-search-results');
    if (!searchResults) return;

    searchResults.innerHTML = `
        <div class="flex items-center justify-center py-10">
            <div class="animate-spin rounded-full h-8 w-8 border-b-2 border-red-600"></div>
        </div>
    `;
    searchResults.classList.remove('hidden');

    try {
        const response = await fetch(`../api/api_search.php?q=${encodeURIComponent(query)}`);
        const data = await response.json();

        if (data.success && data.results.length > 0) {
            renderSearchResults(data.results);
        } else {
            searchResults.innerHTML = `
                <div class="text-center py-10">
                    <i class="bi bi-search text-4xl text-gray-300 dark:text-dark-muted mb-3 block"></i>
                    <p class="text-gray-500 dark:text-dark-text">No results found for "${query}"</p>
                </div>
            `;
        }
    } catch (e) {
        console.error('Search error:', e);
        searchResults.innerHTML = '<p class="text-center py-10 text-red-500">Error connecting to search engine.</p>';
    }
}

function renderSearchResults(results) {
    const searchResults = document.getElementById('global-search-results');

    // Categorize
    const categories = {};
    results.forEach(res => {
        if (!categories[res.type]) categories[res.type] = [];
        categories[res.type].push(res);
    });

    let html = '';

    Object.keys(categories).forEach(cat => {
        // Proper pluralization mapping
        const pluralMap = {
            'Activity': 'Activities',
            'Note': 'Notes',
            'Deadline': 'Deadlines',
            'User': 'Users',
            'Announcement': 'Announcements',
            'Document': 'Documents',
            'Agenda Item': 'Agenda Items',
            'Agenda': 'Agendas',
            'Session': 'Sessions'
        };
        const displayCat = pluralMap[cat] || cat + 's';

        html += `
            <div class="mb-6">
                <h3 class="text-xs font-bold text-red-600 dark:text-red-400 uppercase tracking-widest mb-3 px-2">${displayCat}</h3>
                <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
                    ${categories[cat].map(item => `
                        <button onclick="handleSearchResultClick('${item.action}', ${JSON.stringify(item.data).replace(/"/g, '&quot;')})" 
                            class="flex items-center gap-4 p-4 rounded-xl bg-gray-50 dark:bg-dark-bg/50 border border-gray-200 dark:border-dark-border hover:border-red-500 dark:hover:border-red-500 hover:bg-white dark:hover:bg-dark-card transition-all text-left group">
                            <div class="w-10 h-10 rounded-lg bg-white dark:bg-dark-card border border-gray-200 dark:border-dark-border flex items-center justify-center text-red-600 dark:text-red-400 group-hover:scale-110 transition shadow-sm">
                                <i class="bi ${item.icon} text-lg"></i>
                            </div>
                            <div class="flex-1 min-w-0">
                                <h4 class="font-bold text-gray-900 dark:text-white truncate group-hover:text-red-600 transition">${item.title}</h4>
                                <p class="text-xs text-gray-500 dark:text-dark-muted truncate">${item.subtitle}</p>
                            </div>
                            <i class="bi bi-chevron-right text-gray-400 dark:text-dark-muted group-hover:text-red-500 transition"></i>
                        </button>
                    `).join('')}
                </div>
            </div>
        `;
    });

    searchResults.innerHTML = html;
}

window.handleSearchResultClick = function (action, data) {
    // Close search overlay first
    closeGlobalSearch();

    switch (action) {
        case 'session':
            showSection('sessions');
            if (typeof window.viewSessionDetails === 'function') {
                window.viewSessionDetails(data.session_id);
            }
            break;
        case 'agenda':
            showSection('agendas');
            break;
        case 'agenda_item':
            showSection('agendas');
            // If we have a way to highlight the item, we'd do it here
            break;
        case 'document':
            showSection('agendas');
            break;
        case 'announcement':
            showSection('public-portal');
            break;
        case 'user':
            showSection('users');
            if (typeof window.openEditUserModal === 'function') {
                window.openEditUserModal(data.user_id);
            }
            break;
        case 'deadline':
            if (getCurrentUser() && (getCurrentUser().role === 'Super Admin' || getCurrentUser().role === 'Admin' || getCurrentUser().role === 'Administrator')) {
                showSection('deadlines');
            } else {
                showSection('my-deadlines');
            }
            break;
        case 'note':
            showSection('calendar');
            if (typeof window.openEditNoteModal === 'function') {
                window.openEditNoteModal(data.note_id, data.note_date);
            }
            break;
        case 'reminder':
            showSection('reminders');
            break;
        case 'log':
            showSection('audit-logs');
            break;
        default:
            console.log('Unknown action:', action, data);
    }
};

